DISTRICT_DESCRIPTIONS = {
    "Łacina":            "Łacina — молодой район в составе Ратае (административная единица с 2008 г.), ограниченный улицами Inflancka, Krzywoustego, Jana Pawła II и Baraniaka; трамваи линий 6 и 13 через Rondo Rataje доставляют до центра (Rondo Kaponiera) за 17–20 минут, новая остановка «Łacina» открыта после реконструкции корницкой трассы. Торговая инфраструктура — сильнейшая в Познани: галерея Posnania (220 бутиков, 40 кафе и ресторанов, кино, рейтинг 4,55 балла от Otodom), Leroy Merlin, аптеки и клиники в пешей доступности; Galeria Malta сносится, на её месте девелопер Cavatin строит часовню и жилой комплекс. Безопасность высокая: в рейтинге Otodom 2020 район выиграл в трёх категориях включая безопасность, участок полиции «Nowe Miasto» — на ул. Polanka; жители пишут «чувствую себя спокойно даже поздно вечером». Зелень и спорт: Jezioro Maltańskie в 1,7 км, Termy Maltańskie (аквапарк) доступен автобусом 174 за 6 минут от центра. Школы: СШ № 19 и СШ № 2 (двуязычные классы) в 800–950 м, предшкола № 10 в 800 м — очередей нет согласно отзывам. Хронические проблемы: острая нехватка парковок (девелоперы Nova Łacina не предусмотрели внешних мест, жители конфликтуют из-за стихийной стоянки), шум и выхлопы от кольца Поснании, планируемая новая улица через трамвайные пути делит жителей на два лагеря; цены на жильё — 11 225 зł/м² (новостройки от 12 500 zł/м²), на 3,7 % выше среднего по Познани.",
    "Sołacz":            "Трамвай №11 от остановки Sołacz/Nad Wierzbakiem до Rondo Kaponiera идёт ~24 минуты; дополнительно обслуживают автобусы №160, 164, 182, 193 — но часть улиц (Niestachowska/Grudzieniec) удалена от остановок более чем на 600 м, что вынуждает новосёлов ездить на машине. Парк Sołacki (1911 г.) с прудами, рекой Богданка и велодорожками переходит в лес и озеро Русałka с пляжем, лодочной станцией и кемпингом — зелёный коридор прямо у порога; в парке работает ресторан Port Sołacz (фигурирует в обзорах Michelin). Инфраструктура зрелая: несколько супермаркетов на ул. Wojska Polskiego и Wielkopolska, аптеки, публичные и частные детсады (Otodom поставил Sołacz №1 в Познани по дружественности к детям — 4,39/5), школы без критических очередей. С осени 2024 года в секторе Пулаского–Nad Wierzbakiem введена платная парковка — реакция города на хаос с машинами; жители Рады Осьедля жалуются, что в праздники автомобили реально ездят по газонам парка, разрушая покрытие. Строится кámeral'ный ЖК «Nowy Sołacz» на ул. Дшималы (60 квартир, 3 этажа) и вилльный проект Echo Investment между Niestachowska/Grudzieniec/Litewska — часть резидентов протестует против застройки зелёной зоны; цены на первичке от 10–15 тыс. злотых/м², что делает район одним из самых дорогих в Познани. В 2026 году по Познанскому гражданскому бюджету запланирована реконструкция рекреационных дорожек на северном берегу Русałки; Рада Осьедля активно оспаривает план «Park Golęcin», опасаясь застройки западного зелёного клина.",
    "Umultowo":            "Транспорт — только автобусы: линии 167 (до Rondo Śródka в центре, общее время маршрута ~36 мин), 198, 348 и 911; трамвая нет, ближайшие трамвайные маршруты — в районе Naramowice южнее; в апреле–мае 2025 г. переезд на ул. Умултовской закрывался на реконструкцию, что вызывало серьёзные сбои в движении автобусов — работы завершены, маршруты восстановлены с 16 мая 2025 г. Из инфраструктуры — современный Zespół Szkolno-Przedszkolny nr 9 (ZSP9) на углу Ślazowej/Zagajnikowej/Umultowskiej: 24 школьных класса + 6 групп детсада на ~700 детей, хала спортивная, 4-дорожковая беговая дорожка 80 м — одна из крупнейших инвестиций в образование Познани (25 млн злотых). Главная природная ценность — Jezioro Umultowskie (3,1 га, экологический заказник с 1994 г.) и примыкающий парк при Dworze Umultowskim с каштановой аллеей XIX века; вокруг осьедля обширные леса с сарнами и кабанами, жители описывают район как «деревня в городе»; велоинфраструктура развита слабее центра. Магазины представлены Żabka, Biedronka и Kaufland в пределах района; аптеки и врачи — слабое место: рейтинг доступности медпомощи 3,12/5 (худший показатель по осьедлю), общий рейтинг района 3,94/5, безопасность 4,04/5. Активная застройка: новый ЖК на ул. Maków Polnych (сдача Q4 2025), ведётся разработка местных планов застройки \"Morasko-Radojewo-Umultowo\" (публичные слушания осень 2024) и \"Umultowo Wschód — Jasne Błonie\"; близость кампуса UAM (факультет физики) стимулирует рост новых жилых проектов. Из хронических проблем — стихийные свалки в лесных массивах, часть тростниковых зарослей у озера незаконно засыпана строительным мусором; ресторанная жизнь почти отсутствует — это спальный тихий район для тех, кто ценит природу, а не urban lifestyle.",
    "Strzeszyn":            "Транспорт: автобусы 146, 160, 168, 171 до центра Познани за ~20 минут; станция PKM (Poznańska Kolej Metropolitalna) \"Poznań Strzeszyn\" есть, но всего ~17 поездов в сутки — в час пик лишь 3 рейса с интервалом до 30 мин, что жители считают слабым местом; к декабрю 2027 года запланировано строительство новой железнодорожной связки Strzeszyn–Piątkowo, что должно улучшить ситуацию. Зелень и отдых: главный актив района — Jezioro Strzeszyńskie (33,5 га, глубина до 17,8 м, чистейшее большое озеро Познани): пляж \"Malibu\" с прокатом водного снаряжения, открытым тренажёрным залом, волейболом и баскетболом, сезонной едой и баром; сеть велодорожек ведёт через лес к озеру Rusałka. Образование: в 2025 году открылся крупнейший в Познани образовательный комплекс на ул. Rostworowskiego 15 — Przedszkole nr 201 + Szkoła Podstawowa nr 99, рассчитанный на 32 школьных и 8 дошкольных класса, что частично снимает проблему нехватки мест. Безопасность и атмосфера: Strzeszyn занимает 2-е место среди самых безопасных осьедле Познани (индекс 5,67), кафе и рестораны практически только на территории пляжа (сезонно), в самом районе гастрономическая жизнь скудная — не то что центр. Строительство активное: программа PTBS \"POZnań i zamieszkaj\" — I этап 199 квартир (сдан 2024), II этап 353 квартиры (IV кв. 2025), плюс ЖК Literacka Skwer (190 кв., 10 700–11 900 зл/м²); на форумах жалуются на тонкие стены, слышимость соседей и редкое обслуживание дорог (ямы, квартальные объезды). Парковка у станции PKM только проектируется, пока машины бросают стихийно; район тихий и зелёный, но транспортно зависит от автобусов — без машины жить комфортно, но с оговорками.",
    "Smochowice":            "Транспорт только автобусный: линии 156 (Krzyżowniki–Ogrody) и 186 (Kiekrz–Ogrody) плюс ночные 219/258 до Poznań Główny; трамваев нет, ближайшая электричка — станция Poznań Wola (линия 351 на Szczecin) у северо-восточного края района; до центра (~Ogrody/Ratajczaka) около 25–35 минут на автобусе. Район преимущественно одноэтажной частной застройки с минимальной коммерческой инфраструктурой — из заведений зафиксирована итальянская ресторан Pablo (ul. Kołobrzeska 7), крупных торговых центров внутри нет, ближайшие — вдоль DK92. Главные козыри — природа: пляж Plaża Smocza на Jeziorze Kierskim (прокат каяков, водные велосипеды, воркаут, детская площадка), соседний Lasek Marceliński и Jezioro Strzeszyńskie, велодорожки и спортивный объект с футбольным полем и теннисными кортами. Из учебных заведений — государственная SP nr 57 им. Костшевского, частная школа Olimpijczyk и 6 детсадов (в том числе публичный nr 14 и Tęcza на ul. Czarnkowska 17); очередей в детсады источники не фиксируют явно, но места ограничены. По безопасности район оценивается на 4.01/5, сосед соседа — дружелюбный (3.8/5), однако ДТП на ul. Santocka с 10 пострадавшими и единичные криминальные инциденты имели место. В сентябре 2024 года принят MPZP «Smochowice-Sianowska część A» (4,2 га): разрешена многоквартирная и муниципальная застройка, зарезервированы участки под школу/детсад, запланирован ретенционный пруд; введена зона Tempo 30; жители ранее жаловались на непроходимый тоннель на ul. Leśnowolskiej — единственный путь к школе и аптеке для мам с колясками.",
    "Winogrady":            "Транспорт — сильная сторона района: линии PST (Познаньский Быстрый Трамвай) 12, 14, 15, 16 доставляют до Rondo Kaponiera в центре за 10–15 минут, скорость до 70 км/ч; также ходят автобусы 178, 182, 190; аэропорт Лавица — 11 минут на машине. Инфраструктура советского типа: район панельных домов 1968–1985 гг. постройки (~43 000 жителей), в каждом осьедле по плану была школа, детсад и поликлиника — они существуют, но конкретных данных об очередях в садики найти не удалось; рядом — Galeria Pestka, Carrefour на os. Kosmonautów 104, Biedronka, аптеки в Carrefour и в Pasaż Newa (os. Wichrowe Wzgórze 121A). Гастрономия скромная, но есть: ресторан Cztery Pory Roku с террасой (ul. Winogrady 9), кофейня La Cafeine (ul. Winogrady 28), пиццерия Winogratka (ul. Przełajowa 14), NANO Italia (os. Przyjaźni, ul. Słowiańska 38A), ONI Sushi (ul. Gromadzka 35, открыт январь 2025) — атмосферы мало, это спальник, а не тусовочный район. Зелень — главный козырь: 5 парков (Cytadela — один из крупнейших в Познани, Kosynierów, Gagarina, Czernieckiego, Szelągowski), городской пляж на Шелонге, долина Варты с велодорожками — всё пешей доступности. Хроническая проблема — парковка: дефицит мест признан «нерешаемым» самим председателем спółdzielni Winogrady, машин в разы больше, чем проектировалось в 1970-х; безопасность высокая (оценка 5,9/10 среди районов Познани), тихо, жители называют район «cicha, spokojna okolica». Активная застройка: Murapol Havelia (сдача Q1 2026), Osiedle Hawelańska III etap (ul. Hawelańska 21–25), Nowe Winogrady у Цитадели — суммарно 888 квартир в стройке, сдача до Q4 2027, цены от 392 000 PLN за 26 м²; шум стройки локальный, угрозы массового уплотнения пока нет.",
    "Piątkowo":            "Трамваи PST (линии 12, 14, 15, 16) от конечной Os. Jana III Sobieskiego доставляют до центра за 10–15 минут по выделенной эстакаде (до 70 км/ч); плюс 6 дневных автобусных маршрутов (151, 174, 185, 191, 193, 198) и ночные 201/202/235 — транспортная доступность одна из лучших в городе. Инфраструктура насыщенная: ТЦ Pestka и Plaza (Cinema City IMAX в шаговой доступности), бассейн Atlantis с джакузи и саунами, аптеки и частные поликлиники (Nova-Med, Med-Familia, Hipokrates, IMEDICA) на ул. Обурницкой, Лувминьского, Курпиньского; 8 государственных начальных школ (SP 15, 34, 48, 76, 86) и 2 лицея, детсады на каждом микрорайоне — очередей практически нет. Зелень реальная: лес Piątkówka с резерватом Żurawiniec (прогулки, бег, велодорожки), Park Międzyosiedlowy со скейт-парком и выгулом собак, 6 станций городского велопроката. Район считается вторым по безопасности в Познани, главная боль жителей — парковка: машины блокируют тротуары и подъезды к домам, сотни жалоб в Straż Miejska без видимого эффекта. Активная застройка: ROBYG возводит Początek Piątkowo на 1250 квартир (сдача Q4 2026, цены от 10 950 зł/м²), строится ул. Десzczowa с велодорожками для связи с Morasko — район растёт, шум строек актуален. Кафе и рестораны есть (польская, итальянская, японская, индонезийская кухня), но атмосферная гастросцена сосредоточена скорее в центре — Piątkowo остаётся прежде всего спокойным спальным районом для семей, а не местом вечернего досуга.",
    "Podolany":            "Podolany (5,3 км², ~9 400 жителей) — северо-западное осьедле без трамвая: до центра добираются автобусами 160/164/168/183/907, маршрут 164 ходит каждые ~20 мин до Rynek Jeżycki, на велосипеде ~7 км до Старого Рынка за 20 мин; трамвай запланирован (через больницы на Лутыцкой), старт строительства не ранее 2028–2029 года, пока это только концепция. Инфраструктура есть: Lidl на ul. Obornicka 282–284, Galeria Podolany (ul. Strzeszyńska 63), аптеки, ресторан Wielka Kuchnia (неаполитанская пицца, ул. Szarych Szeregów 16), Restauracja Podolany; атмосфера тихая, не богемная. Школа nr 62 (SP62) имеет хорошую репутацию у родителей и расширяется; детсад nr 155 «Podolanie» плюс ещё 2–3 объекта в шаговой доступности от новых ЖК. Район считается безопасным и семейным, однако имеет промышленный бэкграунд: вдоль ul. Obornickiej — склады и производства, трафик с северных пригородов резко вырос, пробки в час пик. Активно строится: Sielskie Podolany II (Jakon), Reduta Nowe Podolany (EBF, ul. Jasielska), плюс строительство канализации на ul. Obornickiej с перебоями движения до сентября 2025; идут консультации по MPZP для ul. Szarych Szeregów и ul. Karwieńskiej — уплотнение продолжится. Жители на форумах отмечают: тихо, зелено, но без трамвая район «отрезан», а промзона по соседству снижает привлекательность — советуют брать ближе к ul. Strzeszyńska подальше от Obornickiej.",
    "Winiary":            "Трамваи 9 и 11 (конечная Piątkowska) идут через Most Teatralny и pl. Wolności до центра — лinia 11 каждые 10 мин, лinia 9 каждые 20 мин в пиковые часы; плюс 12 дневных автобусных маршрутов (160, 164, 168, 170, 178, 182, 183, 190, 191, 193, 195, 322) и 2 ночных (216, 226) — жители ставят транспортную доступность на первое место среди всех районов Познани. Осiedle застроено блочными домами на рубеже 70-80-х, доминирует \"Rogal\" — один из самых длинных домов города; рядом ЦТ Poznań Plaza (рассматривается расширение, против которого протестует совет осiedla из-за роста трафика и шума). Инфраструктура на самом осiedlu скромная — SP nr 27 и Przedszkole nr 155 \"Polanie\" (оба по адресу os. Winiary 2), магазины базовые, за широкой гастрономией и сервисами идут на соседние Jeżyce. Реализуется активная реновация скверa при ul. Widna (19 деревьев, 4 000 многолетников, 9 000 луковичных, новое освещение и лифт для маломобильных, срок сдачи — май 2026); рядом — Университет природоведческих наук. Безопасность высокая — 4,41/5 по опросу 4 500 жителей, инфраструктура для детей — 4,18/5. Из новостроек: Rezydencja Winiary Etap II (Quadro Development, ul. Wyłom, 6 квартир 51-113 м², строилась с октября 2024, сдача Q1 2026) — точечная застройка без массовой нагрузки на школы.",
    "Naramowice":            "Трамвай линии 3 (открыт 23 апреля 2022) идёт от конечной Błażeja через 8 остановок до пересадки на PST у Курпиньского и далее до центра — суммарно около 20-25 минут; автобусы 144, 146, 167, 171, 182 дополняют сеть, однако восточная часть Наромовиц (Рубеж) до сих пор трамваем не охвачена, там заторы и жители ждут фазы IV. Инфраструктура магазинов и сервисов ещё развивается: на ул. Нарамовицкой есть базовые супермаркеты и аптеки, кафе-сцена скромная — выделяются итальянский ресторан Fortezza в отреставрированном форту Фергюсон (с детской площадкой и садом), суши-бар Nare (ул. Нарамовицка 185c), пиццерия Jasna Rola и турецкий Marhaba; до гастрономического центра города — 3-4 трамвайные остановки. Главное природное достоинство района — Резерват Журавинец в непосредственной близости: торфяное болото с лиственным лесом (ольха, берёза), малыми водоёмами, беговыми и велодорожками, открытым тренажёрным залом — кабаны, белки, богатая орнитофауна; это один из немногих природных резерватов прямо в черте польского города. Застройка идёт в очень высоком темпе: Murapol Zielony Żurawiniec (ул. Сеяни, завершение лето 2026), No To Naramowice (сдан март 2026), Osiedle Witaj, Nove Olendry, конкурс на участок ПТБС на Билицовой — жители на форуме SkyscraperCity жалуются, что дети вынуждены играть в паркингах из-за нехватки дворов, а трафик у Нарамовицкой превратился в \"кошмар\". Детских садов несколько — частные Zielone Pandy (ул. Нарамовицка 222), Tęczowe Misie, Przedszkole Parkowe Skrzaty; публичные школы и детсады есть и получают высокие оценки в рейтингах, однако активный прирост жилья создаёт давление на запись. Перспективы: проектирование фазы II трамвая (продление с Вильчака через Шелонгувску в центр) идёт, полная документация — около 2027 года, начало строительства — позже; пока это главное инфраструктурное ожидание района, который активно растёт, но с отстающей коммунальной базой.",
    "Morasko":            "Morasko — северная периферия Познани (9 км от центра), транспортно слабо связанная с городом: основные маршруты — автобус 188 (до os. Sobieskiego, где пересадка на трамваи PST 12/14/15/16) и экспресс 911, оба с интервалом ~30 минут, суммарное время до Rondo Kaponiera составляет 45–55 минут; район отрезан от города товарной железнодорожной веткой, что дополнительно усложняет доступ. Главная ценность — непосредственная близость к резервату природы \"Meteoryt Morasko\" (55 га, 7 озёрных кратеров от метеорита, дубово-грабовый лес, 440 видов растений) и кампус UAM, который доминирует в застройке района. Инфраструктура минимальна внутри района — магазины и сервисы сосредоточены в соседнем Suchy Las; школа и детсад появились только в 2018 году на ul. Zagajnikowej в соседнем Umultów (инвестиция 26 млн злотых), до этого их не было вовсе. Активная застройка домами в стиле bliźniak (Park Morasko, Wille Morasko, Cichy Zakątek), причём жители соседних кварталов уже жаловались, что девелоперы не успевают строить канализацию под темп жилой застройки. По рейтингу жителей район получил 3.52/5, безопасность для детей — лишь 3.19/5; в ночное время пустые парковки кампуса UAM используются для нелегальных гонок и автосходок, несмотря на неоднократные полицейские вмешательства.",
    "Jeżyce":            "Транспорт: трамваи 17 и 18 плюс автобусы 163, 164, 169, 177, 191, 193; ближайшие остановки Rynek Jeżycki (300 м) и Szylinga (450 м), до центра города около 10–15 минут; три станции электрички (Kiekrz, Strzeszyn, Wola) обеспечивают связь с Познань Главный. Инфраструктура: 13 государственных школ и несколько частных, 4 публичных ясли и 22 детсада (конкуренция за места есть, но выбор широкий); ТЦ King Cross Marcelin на Буковской (120+ магазинов), Rynek Jeżycki с рынком свежих продуктов, сеть супермаркетов; Jeżyce входит в тройку районов Познани с лучшей медицинской инфраструктурой. Зелень и отдых: пешеходный маршрут «зелёные Ежице» — Park Sołacki — Park Wodziczki — Cytadela; велоинфраструктура постоянно расширяется; запланировано подземное пешеходно-велосипедное соединение с Сомачем под железной дорогой (ул. Полеска). Еда и атмосфера: одна из самых модных гастрономических зон Познани — десятки кафе, авторских ресторанов, крафтовых пекарен (Schlebiać, Mówish Mash, SomePlace Else); Rynek Jeżycki — живой рыночный узел с кафе вокруг. Безопасность: район исторически имел сомнительную репутацию, однако с 2015 года статистика преступности устойчиво снижается; сейчас считается безопасным, шум и алкогольные инциденты — ближе к Rynek Jeżycki вечерами. Строительство и перспективы: активная точечная застройка — Epika Jeżyce (ул. Крашевского 26, сдача Q3 2026), Wieża Jeżyce (2-й этап завершён), Pułaskiego 19 (люксовые апартаменты, осень 2025); главная стройка 2026 — Zajezdnia Jeżyce (компания Eiffage): foodhall + бутики + 131 квартира от 30 м²; реновация скверов (ул. Норвида, ул. Костельна) с биоретенцией и зелёными зонами завершается в 2025.",
    "Spławie":            "Spławie — бывшая деревня на юго-востоке Познани (р-н Nowe Miasto), за последние 15 лет превратившаяся в виллово-коттеджный пригород с активной застройкой: работают проекты Nowe Spławie (22 дома, ул. Szczepankowo 137), Osiedle Kameralne II (ул. Gospodarska, 104–120 м²) и Dobrepole (48 таунхаусов, ул. Dobrepole, два этапа). Транспорт — только автобусы: линия 154 (Rondo Rataje – Spławie, конечная, 24 мин), линия 162 и ночная 220, пригородные 431/432/435 на Kleszczewo; с января 2026 года запущен новый минибус 125 по маршруту Szwedzka – Szczepankowo – Gospodarska (введён специально под расписание школы №61) — до трамваев и реального центра нужна пересадка на Rondo Rataje ещё ~15 мин. Инфраструктура района минимальна: есть Szkoła Podstawowa nr 61 (ул. Szczepankowo 72a) и Przedszkole nr 93 (ул. Skibowa 13), крупных супермаркетов (Biedronka/Lidl) в самом Spławie не зафиксировано — ближайшие в Szczepankowo/Ługańska; ресторанов и кафе практически нет, район откровенно «спальный». Из зелени — жёлтый пешеходный маршрут до Swarzędz, водоток Dworski Rów, сельская церковь св. Андрея Апостола; в Познанском гражданском бюджете 2026 года прошёл проект озеленения и освещения именно в этом осёдле. Безопасность в целом спокойная (жители характеризуют как «относительно тихо»), но ведётся установка видеонаблюдения на перекрёстках Rondo Szczepankowo и Ługańska/Szczepankowo — косвенный сигнал о точечных проблемах; парковка свободная ввиду частной застройки. Главные риски для покупателя: слабый общественный транспорт без прямого трамвая (авто — необходимость), стремительная уплотнительная застройка без опережающего развития коммерческой и социальной инфраструктуры, а «10 минут до центра» из рекламы девелопера возможны только на машине в нерабочее время.",
    "Junikowo":            "Транспорт: трамваи 1, 13, 15 до центра плюс PKP-станция Poznań Junikowo (10 мин до Główna поездом); у станции — новый зинтегрированный пересадочный узел (открыт сентябрь 2024) с Park&Ride на 190 машин и 36 крытыми веломестами; автобусы 122, 177, 214, 257, 716, 727, 803 обеспечивают связь с периферией. Зелень: вплотную примыкает Lasek Marceliński — 230 га городского леса с сетью пеших, велосипедных и конных троп, прудом, верёвочным городком и детскими площадками; рядом зона отдыха Szachty. Магазины/сервис: базовая инфраструктура на месте — супермаркеты, аптеки, клиники, банки, кафе и рестораны вдоль ул. Гrunwaldzkiej; ул. Гrunwaldzka = прямой выезд к центру, аэропорту Ławica, автостраде A2 и трассам S5/S11. Школы: СШ №54 (ul. Małoszyńska 38), Przedszkole №38 (ul. Junikowska 15), частные детсады Zielone Pandy; новые ЖК (Junique, Jakon, EBF) наращивают плотность населения на ~3000 человек, обещанный застройщиком детсад в Junique ещё строится — очередь уже реальна. Проблемы: жители на SkyscraperCity называют дорожную сеть «tragedią» — Wieruszowska не соединена с Wołowska, город не обязал девелоперов расширять дороги; парковочный дефицит на старых улочках; активная стройка создаёт шум и разбитые дороги. Перспективы: завершается разработка planu zagospodarowania «Junikowo Południe», возможно расширение застройки на юг; транспортная связность хорошая, но дорожная инфраструктура отстаёт от темпа заселения.",
    "Rataje":            "Rataje — крупнейший жилой район Познани (70 000+ жителей), застроенный панельными домами 1970–80-х, с отличным транспортом: трамваи №5 (до Rondo Śródka), №6, №12 (Winogrady–Centrum–Rataje–Starołęka) и «Pestka» (скоростной трамвай) доставляют до центра примерно за 10–15 минут; параллельно ведётся строительство новой трамвайной линии по ул. Ratajczaka. Инфраструктура насыщена: торговые центры Galeria Posnania и Galeria Malta, HOMEPARK Franowo (OBI, JYSK, Jula), рынок Wielkopolska Gildia Rolno-Ogrodnicza, аптеки DOZ на os. Oświecenia 57 и в Pasażu BETA (os. Piastowskie 17); рядом — школа №18 им. Зофии Налковской и 19 образовательных учреждений в пешей доступности. Парк Rataje (2-й по площади в Познани, открыт 2018) предлагает 9 тематических зон: велотрек, уличный воркаут, паркур, скансен узкоколейной железной дороги и зоны тишины с гамаками; через 10 минут пешком — озеро Мальтаньске (67,5 га) с Термами и горнолыжным склоном. По безопасности Łacina (часть Rataj у ул. Inflancka) получила наивысшую оценку среди всех районов Познани — 4,21 из 5 — и считается самой спокойной и семейной частью города. Главная хроническая проблема — катастрофическая нехватка парковок: район строился в эпоху единичных машин, сейчас на одну квартиру-студенческий съём приходит до 4 автомобилей, и жилищный кооператив вводит платную «Spółdzielczą Strefę Parkowania» — вызывая острые споры среди жителей. Рынок новостроек активен: Panoramiqa (BPI Real Estate, 272 квартиры, 18 этажей, сдана Q3 2024, от ~476 000 злотых) — пример новой высотной застройки; средняя цена м² около 12 600–14 500 злотых, при этом рядом со Stroleki-Minikowo-Marlewo дефицит школ в новых кварталах уже ощущается.",
    "Dębiec":            "Транспорт: трамвай №10 и автобусы 171/175/176/603 до центра за 15-25 мин; электричка с PKP Dębiec до Poznań Główny за 4 минуты; запланирован крупный транспортный узел-пересадка (węzeł Dębiec) и новая трамвайная линия по ул. 28 Czerwca 1956 — район активно интегрируется в систему общественного транспорта. Зелень исключительная: Лас-Дебиньски (261 га), Ласек-Дебецки с историческим фортом IXa, парк Bambrów Poznańskich (2019), парк Дебина — для семей с детьми это главный козырь. Торговая инфраструктура трещит по швам: Galeria Dębiec (двухуровневый ТЦ) сносится с марта 2025 г. — на её месте девелопер планирует 4 жилых блока до 44 м высотой (~850 квартир, 1200 парковочных мест), местный совет и жители подали возражения из-за перегрузки дорог. Железнодорожный шум — серьёзная проблема: три линии PKP (272, 801, 802) через осьедле Зелёны-Дебец превышают норму на 12,9 дБ днём и 16,7 дБ ночью; PKP обещает экран 40 м, жители считают это недостаточным. Школы: Zespół Szkolno-Przedszkolny nr 2, предсад nr 188, nr 22 «Chatka Puchatka», частный «Kaczka Dziwaczka»; очередей катастрофических не фиксируют, но новые ЖК (Red Park — 13-этажки у леса, Zielony Dębiec) плотно застраивают район без опережающего создания учебных мест. Безопасность: исторически имел плохую репутацию «рабочего района», но рейтинг Otodom 2020 — 3,70/5, мониторинг расширяется, новые жители оценивают район как спокойный; главные тревоги сегодня — не криминал, а строительный бум без инфраструктуры и железнодорожный шум.",
    "Ogrody":            "Пл. Варыньского — крупнейший транспортный узел Познани: трамваи 2, 8, 17, 18 до центра за ~15 мин, автобусы 174, 186, 191, 193; пётля Оgrody обслуживает несколько маршрутов одновременно. Осьедле площадью 1,95 км² граничит с улицами Жеромского, Пшыбышевского, Св. Вавжиньца, Буковска: на востоке — многоэтажные блоки, ближе к Смоховице — частные дома. Главная «зелёная» точка — Ботанический сад 1925 года (давший имя осьедлю); Езёро Русалка и Парк Солацки доступны пешком через подземный переход под ул. Св. Вавжиньца. На ул. Шамажевского — крупный психиатрический стационар, Великопольский центр болезней лёгких и туберкулёза, Клинический госпиталь Преображения; при покупке квартиры у выхода из медучреждений шум скорых — реальный фактор. В 2025 году завершена реновация пётли — внутри трамвайного кольца на пл. Варыньского разбит скверик с дорожками, скамейками и цветниками; рядом активно застраивается Nowe Ogrody (Proxin Investment, ул. 5 Stycznia) — несколько очередей уже сдано. Рада осьедля ведёт консультации по плану застройки «Брама Западна — Центрум» (2025), что означает возможные изменения плотности застройки на западной части; в целом район считается спокойным и устоявшимся, с хорошей пешей доступностью магазинов на пл. Варыньского и дефицитом собственного гастрономического сценария — кафе и рестораны концентрируются скорее на соседних Ежицах.",
    "Górczyn":            "Транспорт: пётля трамвайная Górczyn PKM — крупный узел, откуда трамваи №5 (через Rynek Łazarski до Poznań Główny, ~15–18 мин) и №17 (до Małe Garbary в центре), а также автобусы №182, 193, 213 расходятся во все стороны города; электричка Koleje Wielkopolskie до Poznań Główny всего 5 минут, но курсирует лишь днём (первый рейс 06:16, последний около 18:07) — для вечерних поездок только трамвай. Инфраструктура: исторический рабочий район 1925–1929 годов постройки (двухэтажные кирпичные дома), прошедший реновацию; Park Górczyński модернизирован — новое освещение, детская площадка, зоны для пожилых; школа № 10 на ул. Ściegiennego со спортплощадками, открытыми для жителей; два детских сада — муниципальный №67 им. Конопницкой в парке (сад 6000 м²) и частный с ясельной группой от 11 месяцев. Застройка: активная волна девелопмента — ЖК Górczyńska 46 (113 квартир, 44–144 м²), Rembertowska Park III (28 квартир, сдача I кв. 2025), Kameralny Górczyn на ул. Daleka; цена вторичного рынка ~11 817 PLN/м² (+11% за 2024 г.), район на 8-м месте по дороговизне в Познани. Атмосфера и минусы: район исторически рабочий, оценка чистоты и экологии жителями — 2,99/5, что ниже среднего по городу; транспортная зависимость от пётли создаёт риски при ремонтах путей (замещающие автобусы Т5 — переполненные, каждые 15 мин вместо трамвая каждые 3–4 мин); развитой ресторанной сцены нет, основная кафе-жизнь — на соседнем Łazarzu в 2–3 остановках.",
    "Szeląg":            "Транспорт: от ул. Сзелонговской ходят автобусы 174, 183, 190; ближайшие трамвайные линии 12 и 14 на Вильчаке идут через центр (Most Teatralny, Dworzec Główny) — дорога занимает около 15-20 минут. Зелень и отдых: главный актив района — Park Szelągowski на склоне долины Варты (черные тополя 6 м в обхвате, дубовая аллея, детская площадка, открытый тренажерный зал, концертная поляна), а также Ogród Szeląg с баром, гамаками, мастер-классами и концертами прямо у реки; рядом городской пляж и прокат лодок/каяков — Marina Szeląg. Инфраструктура: в непосредственной близости Szkoła Podstawowa nr 27 на osiedle Winiary 2 и интеграционный детский сад Szkółka Małego Dziecka на Szelągowskiej; крупного супермаркета в шаговой доступности нет — жители ездят в Winogrady или ближе к центру. Шум и промышленность: ул. Сзелонговска входит в перечень шумных магистралей Познани (карты акустического мониторинга города); однако планы застройки для треугольника Szelągowska — Wilczak — Czapla ограничивают плотность новой застройки и защищают зеленый клин. Гастрономия: прямо в районе работают Marina (молекулярное мороженое, кафе, каяки) и Ogród Szeląg (бар, концерты, ивенты) — уютная атмосфера у воды, но полноценного ресторанного квартала нет; до Старого города с его барами — 3-4 остановки. Общая оценка жителей: Вингради и Сзелонг относят к тихим и безопасным районам; главный минус — слабая насыщенность ежедневного ретейла и ограниченный прямой трамвай, главный плюс — уникальная близость к реке, паркам и исторической цитадели.",
    "Żegrze":            "Tramwaje 6 i 17 z przystanku Rondo Żegrze docierają do centrum (pl. Ratajskiego, Rondo Śródka) w ok. 15-20 min; uwaga — od listopada 2025 trwa ok. 3-letnia przebudowa Mostu Chrobrego, co powoduje zmiany tras i wydłużenie czasów przejazdu. Infrastruktura handlowa solidna: Biedronka, Netto, Żabka w promieniu 300 m, Galeria Posnania z kinem Helios 1,7 km, park handlowy Franowo (IKEA, OBI, Auchan) ok. 2 km; działa lokalny targ farmerski Ryneczek na os. Orła Białego, co nadaje okolicy minimalną atmosferę. Zieleń i rekreacja są mocnym atutem: Park os. Armii Krajowej 300 m od nowej zabudowy (kort tenisowy, plac zabaw, wybieg dla psów), Jezioro Maltańskie z 5,5-km pętlą rowerową, Termami Maltańskimi i ZOO dostępne kilkoma przystankami tramwajowymi, Las Dębiński rowerem w kilka minut. Szkoły na miejscu: SP nr 64 (400 m), Zespół Szkolno-Przedszkolny nr 19 na os. Stare Żegrze 1, kilka prywatnych przedszkoli (Zielone Pandy, Poznańskie Maludy, Zaczarowane Podróże); kolejki do publicznych przedszkoli typowe dla Poznania. Aktywna budowa: Murapol Osiedle Verde (Wągrowska) — 3 budynki, 666 mieszkań w 8-piętrowych blokach, budynki 1-2 odebrane, budynek 3 planowany na Q2 2026; Agrobex Nowe Żegrze — 132 mieszkania; średnia cena nowego lokalu ok. 740 tys. PLN; inspektorzy odnotowują kilkanaście-kilkadziesiąt usterek na mieszkanie w inwestycjach Agrobex. Osiedle Stare Żegrze to bloki z końca lat 70. (d. Os. ZWM) na Górnym Tarasie Rataj — spokojne, bez wyraźnych problemów z bezpieczeństwem, ale z typowymi dla wielkopłytowych osiedli kłopotami z parkowaniem i hałasem (skargi mieszkańców na plac zabaw i szkoły zbyt blisko budynków).",
    "Wilda":            "Транспорт насыщенный: трамваи 1, 2, 7, 9 и 11 автобусных маршрутов (168, 171, 176, 179, 603), до центра — 15–20 мин трамваем; рядом PKP Poznań Główny для межгородских поездок; с февраля 2021 введена платная парковка на 40 улицах (Traugutta, Pamiątkowej, Langiewicza и др.) — это частично решило хронический паркинговый хаос, когда офисные работники занимали весь район. Гастрономия живая: ул. Wierzbięcice и Rynek Wildecki плотно застроены кафе, барами и ресторанами; Kwyrlejka получила рекомендацию Michelin Guide 2023 и 2024; работают SPOT, Al Capone, Spaghetti Bar Piccolo; кофейная культура развита. Инфраструктура полная: Lidl, Kaufland, Biedronka, Netto, Stokrotka, Żabka, рыночная площадь Rynek Wildecki; публичная больница HCP (им. Иоанна Павла II) и частные клиники Apimed, Lokmed, Wildeckie Centrum Medyczne Plus; спорткомплекс Chwiałka с крытым и открытым бассейном и ледовым катком. Зелень и спорт: лес Las Dębiński, Łęgi Dębińskie вдоль Варты, Park im. Jana Pawła II, Park Drwęskich; район стадиона им. Шица (2,3 га бетона) переобустраивается в зелёную зону — завершение ожидалось в 2025 г. Образование: 7 государственных начальных школ, 15 государственных детсадов + ~10 частных, 2 публичных яслей; на территории района — Politechnika Poznańska и AWF; очередей катастрофических не фиксируется, но публичных яслей объективно мало. Безопасность улучшилась — по полицейской статистике Wilda уже не в топе опасных (лучше, чем Piątkowo или ос. Lecha), однако ночью у Главного вокзала и в отдельных закоулках фиксируются алкогольные инциденты; оценка жителей на Otodom — 3,52/5, детская безопасность — 3,19/5; идёт джентрификация благодаря новым ЖК (Wilda Story — 65 квартир, сдан Q4 2025), что постепенно меняет состав жителей в пользу среднего класса.",
    "Łazarz":            "Łazarz — исторический район у самого центра Познани с отличной транспортной доступностью: трамваи (лин. 6, 10 и др.) по ул. Глоговской до Старого Рынка за 10–12 мин, в границах района — оба вокзала PKP Główny и PKP Zachodni. Главная торговая ось — ул. Głogowska с Рынком Лажарским (Rynek Łazarski): супермаркеты, аптеки, банки, ок. 30 ресторанов и кафе (Barrio, Bistro Złota Kaczka, Masz Babo Placek, wine-bar Mielżyński); Nocny Targ Towarzyski генерирует жалобы жителей на музыку до 4 ночи — Рада Осьедля в 2024 г. добивалась отзыва лицензии на алкоголь. Зелень: Park Wilsona (XIX в., бывший ботанический сад) с Пальмиарнёй — крупнейшей оранжереей Польши; в 2024 г. открыт Łazarski Szlak Rowerowy, связывающий район с вокзалом и Kaponierą. Безопасность исторически ниже средней по городу (оценка безопасности детей 3.18/5), проблемные точки — ул. Głogowska и Kanałowa; введённая зона платной парковки резко снизила хаос с машинами (раньше использование парковочной инфраструктуры превышало 110%), а «тихая» асфальтная крошка на Głogowской снизила шумовой фон на несколько дБ. Активная точечная застройка: инвестиция Cavallia (BPI Real Estate + Revive Poland, первый корпус B6 сдан ноябрь 2025, финал — I кв. 2027), Perła Łazarza и ряд других — средняя цена 2-комн. квартиры от застройщика ок. 603 тыс. злотых; новых социальных объектов (школ, детсадов) в рамках этих проектов не предусмотрено.",
    "Szczepankowo":            "Транспорт слабый: основная связь с центром — автобус 154 (Szczepankowo → Rondo Rataje за 19 мин, далее до центра ещё ~10 мин), плюс линии 123, 431, 432, 435; с января 2026 г. запущен новый минибус 125 до ост. Szwedzka (пересадка на трамвай) — трамвая в самом районе нет, только автобусы. Инфраструктура скромная: аптеки на ul. Skibowa 15C и 11, Apteka Dbam o Zdrowie на Szczepankowo 57; из супермаркетов — Biedronka и Lidl в радиусе доступности; медицина — семейные врачи по НФЗ есть. Образование: SP nr 61 (ul. Szczepankowo 74) и частная HORYZONTY (Szczepankowo 131), детсад nr 93 (Skibowa 13); новый муниципальный детсад на 10 групп (Jagodowa/Roślinna) — тендер на проектирование открыт в августе 2024, открытие через несколько лет. Характер района — бывшая деревня, застроенная частными домами; жители описывают как «деревня в городе»; активно строятся новые коттеджные посёлки (Nowe Spławie, Bocheńska Domy, Osiedle Kameralne II) без сопутствующей инфраструктуры — в 2021–2024 гг. жители жаловались на отсутствие тротуаров и нормальных дорог. Зелень и досуг: рейтинг по рекреации — 2,86/5 (один из самых низких в Познани), ресторанов и кафе почти нет — спальный район без атмосферы; строится спортивно-рекреационная инфраструктура («Rekreacja pod chmurką»). Цена жилья: ~9 531 зл/м² — на 7,5% ниже среднего по Познани (10 002 зл/м²), что отражает периферийность и слабую инфраструктуру.",
    "Stare Miasto":            "Stare Miasto — исторический и административный центр Познани с лучшей транспортной доступностью в городе: трамваи №3, 5, 17 и Познаньский Быстрый Трамвай связывают район с остальными частями города, до главного вокзала Poznań Główny — около 14 минут на трамвае 17, станция PKP Poznań Garbary находится прямо в районе; в нормальных условиях до любой точки центра 20–30 минут, в час пик — до 50. Инфраструктура торговли и услуг максимально насыщена: Stary Browar, Galeria Pestka, Galeria MM, рынок на Placu Bernardyńskim с овощами и фруктами, аптеки и клиники (в том числе детская больница) шаговой доступности; более 30 государственных и столько же частных детсадов, но места в государственных учреждениях ограничены — очереди. Гастрономически район является главной точкой притяжения Познани: сотни ресторанов, кафе и баров на Starym Rynku, ul. Półwiejska и ul. Taczaka (хипстерские заведения с мировой кухней) — жизнь кипит, но для жителей это оборачивается шумом и толпами туристов и студентов по ночам. Главная проблема безопасности — вечернее и ночное время на Starym Rynku и в его окрестностях (рейтинг безопасности района 3,41/5): пьяные компании, бездомные, карманники, зафиксированные нападения у ul. Szkolna/Paderewskiego; улица Półwiejska — наиболее конфликтная точка с 243 полицейскими вызовами только за I квартал 2025 года. Из крупных строек 2025–2026: снос и новое строительство моста Chrobrego через Варту с реконструкцией ul. Estkowskiego и Wyszyńskiego, новые трамвайно-автобусные остановки у Кафедрального собора, пересмотр отводов ливневой канализации на ul. Jarzębinowa — шум и перекрытия в центральной части обеспечены минимум до конца 2026 года; зелёная отдушина — Парк Цитадела (100 га с велодорожками) и Stare Koryto Warty в нескольких минутах ходьбы.",
    "Centrum":            "Район Centrum (Stare Miasto) — транспортный узел Познани: через Rondo Kaponiera и ул. Świętego Marcina проходят трамваи №3, 5, 8, 13, 16, 28; с ноября 2025 идёт строительство новой трамвайной линии по ул. Ratajczaka (срок ~2 года, шум гарантирован), параллельно реконструируется мост Хробрего — часть линий на временных маршрутах; PKP Poznań Główny в пешей доступности. Гастрономия насыщена: сотни ресторанов и кафе вокруг Starego Rynku, в 2025 открылись FRAVE и Czarnomorka, работают культовые Brovaria и COŚ Breakfast — но вечерами пьяные толпы у Рынка создают серьёзный дискомфорт: безопасность района оценена всего в 3,41/5, проблемные зоны — ул. Półwiejska, Jaskółcza, Garbary (кражи, драки, бомжи). Зелени в шаговой доступности немного, однако в 1–2 трамвайных остановках — парк Cytadela (100 га, крупнейший в городе) и Wartostrada — велосипедно-пешеходная набережная Варты. Парковка — катастрофа: свободных мест почти нет, постоянные стройки перекрывают улицы; реновация центра идёт по программе 2017–2027 (уже обновлено 72 000 м² общественных пространств и 1,53 км трамвайных путей), к 2030 запланированы пешеходизация 27 Grudnia и плаца Колегяцкого, новые остановки у Stary Browar и парк на месте ж/д коридоров. Школы (СП №7, 9, 10, 33) и частные садики в районе есть, очередей меньше, чем на спальных окраинах, однако атмосфера «туристического центра» — с шумом от трамваев, стройки и ночной жизни круглосуточно — делает район пригодным для молодых без детей, но спорным для семей.",
    "Śródka":            "Śródka — крошечный (26,2 га, ~1 046 жителей) исторический квартал у подножия Острув-Тумского, с ноября 2025 года переживающий транспортную встряску: реконструкция моста Хробрего (срок ~3 года) закрыла трамвайный маршрут по Эстковского/Вышыньского — вместо него пущен автобус-замена T7 до ост. Марциньковского, а прямые трамваи 5 и 8 идут через мост Святого Роха в центр (~10–12 мин до пл. Вольности); также работают автобусы 213 (до Познань-Главный за 18 мин) и десятки пригородных маршрутов с Рондо Срудка. Гастрономическая сцена живая и плотная: Do Środka (рамен, бао, гёдза), La Farina (свежая паста), Na Winklu (пельмени), Dom na Śródce (кафе), Wspólny Stół (завтраки), Raj & La Ruina, Mar-cel — район полностью перерождён после реновации 2007–2015 гг., туристы и горожане приходят сюда весь день. Зелень и спорт доступны: вдоль Цыбины — 2-километровая экологическая тропа с экспериментальным садом, велодорожки по Гданьской и Быдгоской выходят на Вартостраду (14 км набережной), до Malta (озеро, горнолыжный стадион, аквапарк) — 5–7 минут пешком. Район очень мал: своей массовой торговли (супермаркет, аптека, банк) практически нет — за покупками ехать на Rataje или в центр; обычной начальной школы в Шрудке тоже нет (только школа для глухих на Быдгоской и музыкальная школа при соборе). По безопасности — рейтинг жителей 3,43/5: туристический днём, но безлюдный вечером, жалобы на слабое освещение и отсутствие полиции после темноты; парковка строго платная и дефицитная. Перспективы: реконструкция Рондо Срудка запланирована, строительство новой трамвайной линии по Ратайчака идёт параллельно — стройшум и объездные схемы сопровождают квартал минимум до 2028 года.",
    "Starołęka Mała":            "Транспорт: трамваи 12 и 17 по ул. Старолецкой до Rondo Kaponiera за ~30 мин, электричка PKP Познань Старолека до Познань-Главный за 7 мин — лучший вариант быстрого дояезда; автобусы 171, 176, 189 дополняют сеть. Инфраструктура в наличии: предсадик Parostatek (ул. Старолецка 42), две начальные школы, магазины; но уровень сервиса скромный — район исторически рабочий. Ключевая проблема: с XIX века здесь оседала промышленность (заводы, сортировки отходов, металлоломные базы), жители годами жалуются на шум, запах и пыль в зонах, граничащих с производственными участками; территория у трамвайной петли — публичное распитие, мусор, оценка инфраструктуры 2,77 из 5. Активное переформатирование: в декабре 2025 г. принят MPZP на 80 га вдоль ул. Романа Майа и Старолецкой — бывшие промзоны превратятся в жилые кварталы 5–7 этажей с предсадиком, парком по бывшему железнодорожному полотну, публичным рынком и медуслугами, но строительство только начинается, шум стройки гарантирован на годы вперёд. Уже открыт Park Rekreacji Starołęka Mała (многофункциональное поле, волейбол, воркаут, освещение, видеонаблюдение) — первый рекреационный объект в этой части района. Вывод: район с реальным транспортным потенциалом (PKP спасает) и масштабными планами, но покупать стоит только понимая: ближайшие 5–10 лет — стройка, а промышленное прошлое ощущается буквально.",
    "Starołęka Wielka":            "Транспорт: станция PKP Poznań Starołęka (ул. Starołęcka 57) — 6 минут до Poznań Główny на электричке (60 поездов в сутки, включая IC и TLK); трамвай №12 до центра — 23 минуты; автобус 153 связывает с трамвайными линиями в сторону Unii Lubelskiej; рядом кольцо трамваев на Rondo Starołęka. Район исторически промышленный: до сих пор работают производственные комплексы, смешанная зонировка \"завод рядом с домом\" — это главная претензия жителей; в рейтинге Otodom Starołęka заняла последние строчки по инфраструктуре для детей (2,52 балла) и спорту (2,77), хотя соседство оценили на 3,84. Мегапроект Portowo от Vastint — 1800 квартир в 47 домах на 19 га вдоль Варты (ул. Starołęcka 2), 5–6 этапов строительства с завершением ~2036 года: в планах школа, детсад, марина и публичная пристань; параллельно строятся Starołęcka Dolina (Budnex, ~350 квартир, ул. Śliska), Unii Lubelskiej Vita (Develia, 285 квартир, 5–13 этажей) и Osiedle Kolektyw (Archicom, 132 квартиры, ул. Forteczna) — массовая застройка без готовой социальной инфраструктуры. Зелени мало: главные козыри — лес Dąbinek (Las Dębiński) с дорожками и новый Park Rekreacji Starołęka Mała на месте бывших огородов, а также пешеходный мост через Варту (1903 г.) с видом на реку; по скверам и паркам прямо у домов — пустыня. Коммунальные проблемы: возле транспортного узла хронический бардак — распитие алкоголя, курение на остановках (152 протокола за январь от городской стражи), мусор; бывшая городская свалка на территории района оставила загрязнённые грунты. Bistro KAJA и кафе Deko — единственные заметные точки общепита в самом районе; нормальный выбор ресторанов появится только в рамках Portowo, то есть не раньше 2028–2030 гг.",
    "Główna":            "Главна — рабочий пригород на правом берегу Варты (около 7 км²), сохранивший провинциальный характер: преобладает застройка 1960-х годов, исторический центр района — Rynek Wschodni. Транспорт исключительно автобусный (линии 70, 72, 73, 85), трамвай сюда не доходит — конечная Zawady расположена в стороне; есть станция PKP Poznań Wschód, однако проект трамвайной линии \"Tramwaj Poznań Wschód\" (от Zawady до Poznań Wschód) пока на стадии консультаций без утверждённого финансирования. По рейтингу безопасности среди познанских осьедлей Главна занимает последнее место (3,19/5): жители сообщают о чувстве небезопасности в вечернее время, запущенной инфраструктуре и беспорядке на улицах — район описывается как \"напоминающий 1990-е\". Культурное предложение также худшее в городе (1,95/5): ресторанной и кафейной атмосферы практически нет, развлекательные заведения отсутствуют. Из зелени — Парк им. ксендза Тадеуша Киршке с уличным тренажёрным залом, в остальном зелень ограничена. В перспективе район может выиграть от строительства трамвая (который связал бы его с центром за ~20 минут), однако решение зависит от городского бюджета и привлечения средств ЕС — конкретных сроков нет.",
    "Ławica":            "Транспорт: автобусы 148 и 159 до Познань Главный / Rondo Kaponiera за ~20-25 минут, интервал 20-30 мин, работают с 4:42 до 22:48 — трамвая нет, исключительно автобусное сообщение. Главная проблема района — шум: аэропорт Ławica выплатил свыше 55 млн злотых компенсаций жителям за авиационный шум, Tor Poznań добавляет шум от гонок; с октября 2026 г. вводится ночная тишина 1:00–5:00, но тренировочные самолёты летают весь световой день. Инфраструктура бедная: ряд улиц (Wyszomirska, Tęplińska, Barwicka) до сих пор не заасфальтирован, в бюджете 2025 г. заложено 4 млн зл. на строительство улиц Gryfińska и Wyszomierska, боisko при Modrzejewskiej строится через бюджет obywatelski. Зелень хорошая — Lasek Marceliński в непосредственной близости, Folwark Edwardowo, обширные садовые участки; из торговли и сервиса: две семейные клиники на ул. Rumcajsa 2a, аптеки есть, ресторанов практически нет — по сути kebab и буфет при школе. Школа nr 58 им. Kukuczki — 18-е место в городе, есть, но мест мало; осьедле малонаселённое (~6 400 жителей на 14 км²), тихое, но аэропортовый шум и нехватка асфальта, гастрономии и развитой торговли делают его подходящим скорее для автомобилистов, ценящих близость к природе, а не для тех, кто хочет жизни в шаговой доступности.",
    "Suchy Las":            "Транспорт: автобусные линии ZTM Poznań 901 (Złotniki–Os. Sobieskiego), 905 и 907 (Chludowo–Os. Sobieskiego) с интервалами 40–50 мин в будни, поезд Koleje Wielkopolskie от Poznań Główny занимает ~8 мин — самый быстрый вариант. Главная проблема района — муниципальный полигон ТБО (wysypisko) у ул. Meteorytowa: жители годами жалуются на невыносимый запах, доходящий до школ и домов, проводили блокады въезда и собирали подписи под петицией; полигон должны были закрыть в 2016 году, но вместо этого построили биокомпостную установку и заложили три новые секции. Коммерческая инфраструктура скромная: Biedronka на Obornicka 85 и Nowy Rynek 6, единственное заметное заведение — Bistro&Cafe Gajowa 12 с кегельбаном; гастрономическая жизнь практически отсутствует. Зато природа богатая: 2/3 площины гмины занимает военный полигон (территория Natura 2000), рядом озеро Kierskie и Bike Park Morasko, есть муниципальный прокат велосипедов в Złotniki. Строительство активное: Nickel Development (Osiedle Poziomkowe), PB Lechbud, Osiedle Pod Gwiazdami — плотность застройки растёт, план ogólny с 1014 зонами ещё не принят окончательно. Школы и детсады есть (Przedszkole Leśnych Ludków и несколько частных), а также водный парк Octopus и спортзал — но вопрос запаха с полигона остаётся ключевым риском для качества жизни.",
    "Złotniki":            "Собственная ж/д станция (линия 356) — до Познани-Главной 8-12 мин. Активно застраивается коттеджами в 500 м от леса Natura 2000; детсад, школы и магазины в пешей доступности. Жители новых осаджений уже предупреждают: следующие волны застройки грозят ещё большими пробками на выезде.",
    "Puszczykowo":            "Транспорт: две станции PKP — Puszczykowo (север) и Puszczykówko (центр), электричка до Познань Главный за 17–20 минут, отправление примерно раз в час; автобус 651 до конечной Дембец занимает ~30 мин, но оба маршрута тормозят на нескольких железнодорожных переездах на трассе 430 — в часы пик пробки обычны. Инфраструктура скромная: аптеки, небольшие магазины, больница (парковка у неё стала скандалом — 90 злотых за 3 часа по данным 2025 г.); крупных супермаркетов нет, за Biedronkой/Lidlem едут в Познань или Лубонь. Школы: две государственные (SP1, SP2) и не менее 5 детсадов — как государственных (Czarodziejski Zamek), так и частных; очередей в частные нет, в муниципальное — данные не публикуются открыто. Природа — главный козырь: город буквально вписан в Великопольский национальный парк, 11 озёр, лесные велодорожки, верёвочный парк, каяки по Варте — уровень зелени исключительный для пригорода. Застройка жёстко контролируется планом зонирования (69 MPZP, в 2025 г. принят первый в Великопольше Plan Ogólny), массовых ЖК нет — преобладает малоэтажное строительство на участках; цены на нерухомость завышены (250–350 злотых/м² земля, квартиры 4800–6000 злотых/м²). Жители на форуме ценят тишину и камерность ~9 000-жительного городка с атмосферой довоенных вилл, но жалуются на слабое финансирование дорог (многие улицы без асфальта) и отсутствие рабочих мест — все едут работать в Познань.",
    "Kiekrz":            "Транспорт: автобусы 186 и 195 от конечной Ogrody до Kiekrz за ~28 минут (дневные), ночной маршрут 219 через Rondo Kaponiera; электричка Polregio от ст. Kiekrz до Poznań Główny за 11 минут — но рейсов мало (несколько в день), что делает её ненадёжной для ежедневных поездок; в часы пик Chojnicka (трасса 431) стоит в пробках. Магазины: Biedronka и Galeria Kiekrz покрывают базовые нужды, но крупные ТЦ (King Cross Marcelin, Galeria Podolany) — только на автобусе в Jeżyce; аптеки и базовые сервисы есть. Школа: SP nr 28 им. Корнела Макушиньского (Chojnicka 57) — прямо в осьедле, частные садики Ptyś и Familijne Ranczo, но от новостроек часть объектов на расстоянии 2+ км. Рекреация — главный козырь: Jezioro Kierskie с двумя официальными пляжами (Plaża Parkowa и Smocza) с лифтгвардами, прокатом оборудования, мониторингом; яхт-клубы, кайтсёрфинг, рыбалка; велодорожки к озеру есть, но выделенного велошоссе в центр пока нет (в планах). Проблемы инфраструктуры серьёзные: часть улиц — грунтовые, нет ливневой канализации, у ~40% домов нет подключения к водопроводу Познани, часть без газа — типичная застройка «дачный посёлок стал жилым». Строительный конфликт: девелопер строит апартаменты прямо у берега озера (ул. Wilków Morskich), жители подали петицию мэру и вышли на протест; параллельно строится производственно-складская халла на ул. Dojazd. Перспективы: идёт реконструкция железнодорожной пригородной обводной линии (участок Kiekrz–Piątkowo, бюджет 1,4 млрд зл.), что в перспективе улучшит транспортную связность; характер района — тихий, преимущественно частные дома, атмосфера «деревни у воды» в 12 км от центра, рестораны и кафе единичные, ночной жизни нет.",
    "Bolechówko":            "Bolechówko — это небольшая лесная деревня (leśniczówka) в gmina Czerwonak / Murowana Goślina, ~16 км к северо-востоку от Познани, на западной опушке Пущи Зелёнки. Транспорт: автобусы ZTM линий 341, 342, 348 до Мурованей Гослины и Познани; ближайшая станция PKP — Bolechowo (поезда Koleje Wielkopolskie до Poznań Główny, ориентировочно 25–35 минут в пути); без собственной машины жизнь затруднена — частота рейсов низкая. Инфраструктура почти отсутствует: ни супермаркета, ни аптеки, ни кафе в самом Bolechówko нет — всё это в ближайших Bolechowo или Czerwonak (5–8 км); школа — Zespół Szkół в Bolechowo. Природа исключительная: рядом Jezioro Bolechowskie (6 га, дикое лесное озеро без пляжа и удобств, доступ по лесным грунтовым тропам), велосипедные и пешеходные маршруты Пущи Зелёнки, бобры, олени, краснокнижные птицы. Застройка одноэтажная, малоэтажная, тихая — в 2024–2025 гг. активных ЖК-проектов не зафиксировано; gmina разрабатывает новый план общего зонирования (plan ogólny), что может изменить плотность застройки. Район подходит тем, кто сознательно выбирает лес и тишину при наличии автомобиля; для семей с детьми без машины и с потребностью в сервисах — неудобен.",
    "Lusówko":            "Lusówko (gmina Tarnowo Podgórne, ~20 км западнее центра Познани) обслуживается автобусами ZTM линий 814 и 815 до конечной Poznań Ogrody (западный Познань, не центр), при этом линия 815 делает всего 8 рейсов в день (3 утром, 4 днём, 1 вечером) — в пиковые часы реальных альтернатив мало; линия 805 (с сентября 2025) добавила связь через Юниково, железной дороги PKP в посёлке нет; машиной до центра Познани около 20 минут по ул. Буковской. Инфраструктура: супермаркет Dino в шаговой доступности, небольшая торгово-сервисная зона на Osiedle Rozalin, итальянский ресторан у въезда, аквапарк Tarnowskie Termy в 5 км — но за крупным шопингом нужно ехать в Познань или Тарново Подгурне. Из плюсов — Jezioro Lusowskie с 9 км береговой линии, песчаным пляжем, прокатом SUP/каяков, лесными беговыми трассами и велодорожкой по кругу; дворец Янковице в 5 минутах езды с бесплатным верёвочным парком. Образование: публичная начальная школа (664-е место в Польше, 2-е в районе), 2–3 предсоцэдения (в т.ч. частное «Зелёный холм»), отзывы о заведующей одного садика негативные. Застройка активная: несколько девелоперских проектов (Zielone Lusówko, Akropol, Osiedle Familijne), на Osiedle Morskie часть дорог до недавнего времени оставалась грунтовой; участки в рекреационной зоне облагаются повышенным налогом на недвижимость. Gmina Tarnowo Podgórne заняла 1-е место в Великопольше в рейтинге 2025 года и входит в число богатейших гмин Польши по доходам на жителя (5752 злотых/чел.), что означает стабильные инвестиции в дороги и инфраструктуру — реальная стройка и шум новых кварталов в ближайшие годы продолжатся.",
    "Lusowo":            "Историческое село у озера Лусовске: пляж, леса, велодорожки. Автобусы 802/804 до Познани ~25-35 мин. Более тысячи жителей подписали петицию против застройки лесного участка. Плюсы — природа, тишина, доступные цены; минусы — часть дорог не асфальтирована, главная дорога требует реконструкции.",
    "Rokietnica":            "Транспорт — главный козырь: пригородный поезд Koleje Wielkopolskie до Poznań Główny занимает 13–15 минут (первый рейс из Rokietnicy в 05:01, последний в 21:01); на автомобиле по обводнице — 15–20 минут; автобусы ZTM линий 832, 835, 882, 893 связывают сёла гмины с Познанью, после реструктуризации в сентябре 2025 г. их количество и маршруты расширены. Магазины в самой Rokietnicy представлены Biedronkой, Fresh, Delikatesy Centrum, Piotr i Paweł и Rossmannem; аптеки и базовые сервисы есть, однако с доступностью врачей-специалистов и учреждениями для детей ясельного возраста и пожилых — официально признанные дефициты, отражённые в Стратегии развития гмины 2021–2030. Школьная инфраструктура относительно полная: начальная школа им. Бжехвы, несколько детских садов («Bajeczka», «Cztery pory roku», сады в Mrowino и Napachanie), техникум и лицей — но очереди в предсадиковые учреждения растут вместе с населением (сейчас ~15 700 жителей, динамика роста высокая). Зелень умеренная: Polana Rumpuciowa (скейтпарк, памптрек, инклюзивная площадка), спорткомплекс Rokietnicy, охраняемый ландшафтный район Pawłowicko-Sobocki и Jezioro Kierskie Małe — но благоустроенных парков и пешеходных дорожек за пределами центра гмины явно не хватает, ходники и асфальт во многих улочках отсутствуют. Гмина — пример интенсивнейшей субурбанизации: поля массово превращаются в ЖК, действует 214 местных планов застройки (покрывают 63% территории), стройки идут активно, инфраструктура за приростом населения не успевает; тяжёлой промышленности и экологических проблем нет, уровень безопасности высокий. Кафе и ресторанная жизнь скромная — это тихий пригород, а не городской район с атмосферой; зато цены на недвижимость заметно ниже познанских, а за сегмент или дом-близнец с садом в 2025 г. просили столько же, сколько за квартиру в Познани.",
    "Tarnowo Podgórne":            "Транспорт: автобусы ZTM/TPBUS — линии 801, 802, 811, 812, 813, 821, 822 и др. до Познани (конечная Ogrody или Junikowo), линия 812 достигает Poznań Ogrody примерно за 12 минут; в конце 2024 года анонсирована масштабная реформа сети с новыми линиями 805 (Tarnowo → Wysogotowo → Junikowo) и 814 (Lusówko → Tarnowo → Ogrody) и почасовым интервалом, но дата запуска пока не окончательная. Гмина — крупнейший работодатель-кластер Великой Польши: 55 000 рабочих мест при 27 000 жителей, здесь Amazon (до 5 500 сезонников), Prologis, MAN, Scania, Volvo, Coca-Cola, Mondelez, Imperial Tobacco — 450 га промышленных территорий вплотную к жилой застройке, что создаёт хаотичный облик и реальные конфликты: в 2020 году зафиксированы жалобы на запах от компостирующего завода, в январе 2026 года произошёл крупный пожар на складском комплексе. Образование: школы в Баранове, Пшезьмерове, Лусовку, Лусове и центре Тарнова, с 2020 года — собственный техникум; предсадики (Kaczuszka, Bajkowa Akademia, Malowane Słonie и другие) — электронный набор через nabor.pcss.pl, конкуренция за места есть, но острой очереди на годы вперёд официальных данных нет. Зелень и отдых: дворец в Янковице с 18-гектарным парком, верёвочным парком и уличным тренажёрным залом; велодорожка Tarnowski Łącznik; сама гмина сельско-промышленная, лесов и озёр в пешей доступности немного, природа — скорее на выездах. Инфраструктура и строительство: в 2025 году бюджет капитальных вложений — 73 млн злотых (реконструкция ул. Кasztanowej, расширение школы, новые сельские дома культуры); завершены ЖК Osiedle Tarnowo Centrum и Zielona Przystań II Baranowo, ещё 4 объекта в стадии строительства; цена м² на вторичном рынке — около 9 238 злотых, от 324 000 злотых за квартиру. Главный минус по отзывам жителей форума istrefa.com — соседство жилых кварталов с логистическими хабами и интенсивный грузовой трафик на Poznańska; плюсы — низкая безработица, хорошая коммунальная служба (вывоз мусора оценивают на 90%), активная гражданская жизнь и относительно тихий характер для семей, готовых мириться с промышленным окружением.",
    "Przeźmierowo":            "Przeźmierowo (gmina Tarnowo Podgórne) — около 11 км к западу от центра Познани; автобусы ZTM линий 802 и 812 довезут до центра примерно за 26 минут, на машине в пробки Рынковой улицы (ul. Rynkowa) в часы пик — дольше; обещанная объездная дорога так и не построена. Из магазинов на месте: Chata Polska и Netto, в 5 минутах — Auchan в Сводзимье и Biedronka/Dino в Барануве, строится Lidl. Инфраструктура здравоохранения — две частные клиники (Med Lux на Рынковой и Vita Longa на Огродовой); начальная школа и два детсада есть прямо в посёлке, но при активной застройке очереди растут. Главный бич — самолёты аэропорта Лавица пролетают над посёлком в среднем каждые 20 минут днём в летний сезон; жители годами добиваются ограничений, аэропорт ввёл лишь ночной запрет (01:00–05:00). Гастрономия скромная: Karczma u Tomasza и арт-кафе PoemaCafe; ближайший лес — Лас-Закшевски (доступен через Домброувку). Застройка активная: Przeźmierowo Park, Projekt Przylesie и другие — инфраструктура не успевает за ростом населения.",
    "Skórzewo":            "Автобусы ZTM 727 (Junikowo — Palędzie/Dworzec) и 729 (Skórzewo/Szarotkowa — Dopiewo/Dworzec) — основной транспорт; с января 2026 добавлена линия 728 с прямым выходом на Познань; до центра на автобусе ~26 мин, на машине ~10 мин, но Познаньска улица стоит в пробках в часы пик — новых коллекторных дорог в гмине Dopiewo не строили несколько десятилетий, жители жалуются на хаос на перекрёстках. Торговля закрыта: Biedronka, Netto, Lidl, Chata Polska + Galeria Mallwowa (Piotr i Paweł, Rossmann, Empik, Pepco, фитнес), но гастрономия скудная — из заметного только Restauracja Pub Przebieralnia и семейный Smakosz. Две школы (SP nr 1 им. Шопена, SP nr 2 им. Падеревского) и несколько детсадов работают, но местные активисты ещё с 2015 г. фиксируют: под новые осидла типа Grafitowe резервировали менее 2000 м² под образование — расширение существующих школ «практически невозможно», а строительство новой обойдётся в десятки млн злотых (пока не реализовано). Застройка не останавливается: Aurora Park (сдача IV кв. 2025), Osiedle Życzliwe, Domy Szeregowe этапы III–IV, Grafitlove — стройпылью жалуются на улицах с грунтовым подъездом; вывоз биоотходов только 2 раза в месяц (против еженедельного в Познани), тарифы ЖКХ выше городских. Рекреация — Orlik в 320 м, беговая дорожка, спортплощадки — есть; крупных парков или озёр в пешей доступности нет, лесной массив у Dopiewo в нескольких км. Трамвай в Скожево не планируется; перспектива — новые платформы PKP в соседнем Dopiewiec и продолжение уплотнения застройки по активно меняемым MPZP (Skórzewska/Stawna/Poznańska, Sadowa/Gruszowa/Dębowa) — район растёт быстро, инфраструктура за ростом не успевает.",
    "Dopiewo":            "Пригород Dopiewo (gmina, ~30 000 жит., рост с 8 670 в 1990 г.) — типичная жертва собственного успеха: электричка Koleje Wielkopolskie до Познань Главный за 16 минут (несколько рейсов в день, Park&Ride у станции), автобусные линии 729, 790–799 в систему ZTM Познань, но утром до 8:00 и после 16:00 дорога через Скожево или Домброувку на машине — «маsakra» (цит. жителей): S11, Познаньска и ж/д-пути слышны постоянно, рядом грузовая ж/д-рампа в Палендже работает с рассвета до позднего вечера, включая субботы, PKP платит ежегодные штрафы за шум как абонплату. В Скожеве есть Biedronka, Netto, Lidl, Chata Polska, Galeria Mallwowa (Piotr i Paweł, Rossmann, Empik, Pepco), фитнес-центр; в Домброувке — два торговых центра (Stokrotka, Galeria Dąbrówka) и рестораны, но бассейна нет — за ним едут в Тарнув-Подгурны или Познань. Школы переполнены: начальная в Домброувке работает в две смены, 70 учителей, очередь в дошкольные учреждения реальная; в 2024 г. началась пристройка новой гимназии на ул. Лёнкова. Бюджет на дороги — минимум 15 млн злотых в год (2026–2029), большинство гминных дорог до сих пор грунтовые или щебёночные; рядом с Домброувкой — Лес Закжевски (велодорожки, бег, прогулки), 12 минут до Тарновских Терм (аквапарк). Gmina активно строится — ЖК Cytrusowe, Grafitowe, Przyjazne, Grunwald в Скожеве; инфраструктура хронически отстаёт от темпов застройки.",
    "Dopiewiec":            "Транспорт слабый: автобус ZTM линии 729 (маршрут Ogrody — Dopiewiec — Dopiewo/Dworzec Kolejowy) идёт ~46–55 мин до центра, ходит с 05:15 до 23:15, но только раз в час; PKP-станция находится в соседнем Dopiewo — оттуда Koleje Wielkopolskie до Познани быстрее, но пешком до станции далеко. Инфраструктура критически скудная: единственный магазин в деревне — маленький, дорогой, жители на форуме mojedopiewo.org жалуются на «монополию» и товары с истекающим сроком; Biedronka — в Dąbrówka, Netto и Stokrotka — в Palędzie, аптека и банк есть, но ехать надо. Школа (im. Marii Konopnickiej) переполнена — жители северной части посёлка (Leśna Polana) перенаправляются в Dąbrówka; расширение школы застряло в бюрократии и оценивалось в 7 млн злотых из муниципального бюджета; предсадочная очередь существует. Застройка идёт агрессивно: запланировано 9 блоков по 56 квартир (~504 квартиры, >1000 новых жителей), 110 га зонировано под жилую застройку; канализация дотянута только до части улиц (Jesionowa, Wierzbowa, Olchowa и др.) в 2023 г., дороги и тротуары к участкам во многих местах отсутствуют. Плюсы: ~60 км маркированных велотрасс по лесам, близость буферной зоны Wielkopolskiego Parku Narodowego, рекреационная зона «Leśne Stoliki» на ul. Wierzbowa, молодая демография (средний возраст 35 лет), цена м² жилья около 10 230 злотых. Итог: тихая деревня с лесом и дешёвой землёй, но без нормального магазина, с перегруженной школой, слабым транспортом и стремительной застройкой без опережающей инфраструктуры — типичный «bedroom village» с нарастающими проблемами роста.",
    "Koziegłowy":            "Транспорт: трамвая нет — только автобусы (линии 320, 321, 322, 323, 396, 398 днём и ночная 237); маршрут 320 идёт до Rondo Śródka, время до центра Познани — 15–25 мин на автобусе или ~10 мин на машине вне пробок; до 2029 года строится новый интегрированный транспортный узел Poznań Koziegłowy (30 млн злотых, средства ЕС) с P&R и B&R, плюс запланирована остановка PKM на грузовой обводной дороге. Магазины: Biedronka, Aldi, Carrefour, Dino (жители жаловались на просроченные продукты в Dino), аптека, отделения банков, мясная лавка, рынок — крупного универмага типа \"всё в одном\" нет. Природа и спорт: прямой выход в лес Puszcza Zielonka пешком, река Warta рядом, велодорожка Koziegłowy–Kicin строится (2024), модернизированный бассейн (1,2 млн злотых), комплекс Orlik с мультифункциональными полями, скейтпарк — жители хвалят \"bliskość lasu, cisza, spokój\". Школы: Szkoła Podstawowa im. Roweckiego, 2 муниципальных и 2 частных детских сада, репутация хорошая, серьёзных жалоб на очереди в открытых источниках не выявлено. Специфика: на территории посёлка расположен исправительный колонии (zakład karny), запах от очистных сооружений исторически был проблемой — по данным 2015 года беспокоит лишь несколько раз в год на трассе в сторону Познани; управляющая компания CzTBS под критикой жителей из-за роста тарифов в 2026 году. Перспективы позитивные: бюджет инвестиций гмины Червонак в 2024 году — 67 млн злотых, активное строительство дорог и веломаршрутов, транспортный мегапроект до 2029 года существенно улучшит связь с центром.",
    "Biedrusko":            "Biedrusko (gmina Suchy Las) — деревня в 7 км от границы Познани и ~15 км от центра: два автобуса ZTM — линия 911 (Rondo Śródka — Biedrusko/Park, ~41 мин, курсирует с 04:23 до 22:45) и линия 348 (~25 мин до os. Sobieskiego, интервал 30 мин в час-пик) — единственный общественный транспорт, трамвая и PKP нет, в час-пик пробка на узле Нарамовице. Из магазинов — только Biedronka на ул. Познаньской и мелкие лавки; за нормальным супермаркетом надо ехать 11 км до Сухего Ласа (галерея Сухолеска, несколько сетей). Есть государственная школа + предшколе (Zespół Szkół im. 7 Pułku) и частная начальная школа; поликлиника NZOZ по договору с NFZ. Главная специфика и главный минус: три стороны деревни окружены военным полигоном (закрыт 24/7, штраф 5000 зл за нарушение), стрельбы с боевыми патронами и взрывами проходят пн-сб в 08:00–15:00 и 18:00–00:00 — взрывы слышны даже в самом Познани. Из плюсов — зона Natura 2000, леса, река Варта, пруды; активная застройка: Osiedle Jesionowe (Akropol, 200+ домов), Osiedle Aurinia (87 квартир 3700–4900 зл/м²), Osiedle Błękitny Staw — часть новых осёдлей без нормальных дорог. Для жизни без машины район не подходит категорически.",
    "Kobylniki":            "Kobylniki — деревня в гмине Rokietnica к западу от Познани, обслуживается автобусом ZTM линии 893 (маршрут Kobylniki/Tarnowska — Żydowo/Pętla, около 38 минут до пересадочного узла Rokietnica/Węzeł Przesiadkowy, откуда дальше в центр); в районе также ходят линии 832, 882 и 835, связывающие гмину с Познанью, но частота невысокая — основной вариант для ежедневных поездок это личный автомобиль по Zachodniej Obwodnicy. Из инфраструктуры есть начальная школа (Szkoła Podstawowa im. Fryderyka Chopina), но магазинов, аптек и кафе почти нет — за всем этим едут в Rokietnicу или Познань. Главный плюс — Jezioro Kierskie (285 га, крупнейшее природное озеро в административных границах Познани) в шаговой доступности, развитая сеть велодорожек вокруг озера и леса. Активная застройка: девелопер Creo Development ведёт проект Orzechowa Osada (квартиры 42–79 м² от 369 350 злотых, ~8 231 злотый/м²), Statmid строил бутик-апартаменты Na Winklu; при этом часть территории до сих пор без канализации и газа, есть грунтовые дороги. В разработке — MPZP (местный план застройки) для района улиц Szkolna и Karolewska, а также расширение улицы Działkowa; жители на форумах отмечают тишину и природу как главные достоинства, но называют бедность инфраструктуры и зависимость от машины главными недостатками.",
    "Zakrzewo":            "Zakrzewo — деревня в гмине Допево, примерно в 5 км западнее границы Познани (за западной объездной), доступ к центру только на автобусе 729 (также 257 и 796) с 4 остановками в самой деревне; поездка до конечной Ogrody занимает около 51–55 минут, в будни примерно 16 рейсов в день (нерегулярно, около 1 раза в час), в выходные — заметно реже, трамвая нет. Из магазинов — только Biedronka на ул. Радзеёвской 3 и аптека DOZ на ул. Осьедловой 19; за большим шопингом ехать до Galeria Dąbrówka (3 км) или Galeria Mallwowa в Скожеве (6,7 км). Прямо у деревни — Лас Закшевский (Lasy Zakrzewskie) с пешеходными маршрутами и деревянными вышками-амбонами, плюс футбольное поле, баскетбольная площадка, две детские площадки и уличные тренажёры. Дошкольная инфраструктура есть: публичный детсад «Лесные Дюшки» (ул. Длуга 57), частный «Лесна Хатка Пухатка» (ул. Зацише 4), два яслей; школьный комплекс — Zespół Szkół на ул. Лесьной 3A. Застройка активная: работают девелоперы Quertos (16 квартир, Zielone Zakrzewo), Akropol Inwestycje (таунхаусы, ул. Длуга), PB Lechbud и Jandach — деревня быстро превращается в пригород, но отставание инфраструктуры (транспорт, сервисы) от темпов строительства ощутимо; ресторанов и кафе практически нет, атмосфера спальной загородной зоны.",
    "Jelonek":            "Jelonek — деревня в гмине Сухы-Лас (Suchy Las), Познанский повет, ~9,7 км к северу от центра Познани по ул. Оборницкой (трасса № 11); это не городское осьеле Познани, а пригородное поселение. Транспорт: автобусы ЗТМ линий 253, 904, 905 с остановки Jelonek/Obornicka идут через Мораско и Сухы-Лас до конечной Os. Sobieskiego — расчётное время до центра Познани около 35–45 минут; с 2019 года маршруты включены в единую тарифную зону A+B ЗТМ, трамвай и PKP через Елонек не проходят. Магазины и сервисы: ближайшие Biedronka (ул. Оборницка 85) и Lidl (ул. Оборницка 127) — в соседнем Сухы-Ласе, в 1–2 км; там же аптеки DOZ и Эскулап; в самом Елонеке коммерческой инфраструктуры минимум. Застройка и перспективы: активно строится коттеджный комплекс Ostoja Jelonek (дома 150–184 м², цены 750–900 тыс. злотых), в 2024 году стартовал I этап велодорожки вдоль ул. Оборницкой (Борувкова–Нектарова), II этап — до ул. Павловицкой — запланирован; природный памятник «Дембы Марьяновске» (88 дубов) и окружающие леса делают район зелёным. Школы: Елонек входит в обвуд Szkoła Podstawowa nr 1 им. Войцеха Богуславского в Сухы-Ласе; муниципальный детсад — Przedszkole Leśnych Ludków в Сухы-Ласе; специфических данных об очередях нет, но гмина активно растёт и давление на места увеличивается. Общая характеристика: тихий, зелёный, лесной пригород для тех, кто выбирает дом с участком, однако отсутствие трамвая и прямого ж/д сообщения делает личный автомобиль практически обязательным — автобусы ходят нечасто и зависят от пробок на Оборницкой.",
    "Siekierki Wielkie":            "Siekierki Wielkie — деревня в гмине Костжин Великопольский (не в границах Познани), ~15 км от центра, транспорт: автобус MPK лinia 486 (Свожэдз/Вензел Пшесядковы — Сьекерки-Вельке/Костёл, ~26 мин, работает с 04:23 до ~22:30, но действует не тариф ZTM, а отдельный тариф Swarzędzkie Przedsiębiorstwo Komunalne, что означает отдельный билет); плюс пригородная электричка Koleje Wielkopolskie от Познань-Гарбары до Пачково (ближайшая станция к посёлку) — около 16 мин, раз в час. Инфраструктура минимальная: есть школа-основа (SP im. Pauliny i Augusta Wilkońskich), публичный детсад (новое здание построено в 2022 году на ул. Школьной) и частный детсад \"Слонечко\", аптека, небольшие магазины, парикмахерская, пекарня, церковь — но супермаркетов и банков в самом посёлке нет, за ними едут в Костжин или Познань. Активная застройка: девелопер Partner Developer возвёл 50+ таунхаусов по ~96 м2 на участках ~230 м2, работает \"Осьедле Тихе\"; на форумах жаловались на девелопера Prekson (неработающий домофон, отсутствие освещения после сдачи). Природа — главный козырь: посёлок окружён лесами и полями, рядом ПКП Пачково открывает доступ к озёрам района Костжин; тихо, малолюдно, без промышленных объектов рядом. Минусы для городского жителя: нет кафе, ресторанов, культурной жизни; автобус 486 ходит не каждые 10 минут (интервалы 1–2 часа в неудобное время), без машины жить сложно; само понятие \"пригород Познани\" здесь условное — административно это другая гмина.",
    "Kamionki":            "Автобус 527 от Старолеки ~34 мин с интервалом 40 мин. Зелёная местность, окружена лесами, близость A2 создаёт фоновый шум. Часть новых улиц без асфальта и канализации. Магазины и школы — в Корнике или Борувце.",
    "Rabowice":            "Rabowice — деревня в гмине Swarzędz (повят Познаньский), 1619 жителей (2024), ~15 км от центра Познани: единственный общественный транспорт — автобус 407 (Jasin/Rabowicka Pętla → Rondo Śródka, ~25 мин), но он ходит лишь 3 раза в день по будням и субботам, без воскресений, тариф не ZTM — то есть место почти полностью автомобильное. На пешей доступности только Żabka и пекарня; супермаркеты (Lidl, Kaufland), аптеки, врачи и Leroy Merlin — в Swarzędzu в 2 км; ближайшая государственная начальная школа — в 4,5 км (Zalasewo или Swarzędz), в самих Rabowice есть лишь частный детсад на ul. Bukowa 2. Район активно застраивается: работают несколько девелоперов одновременно (Zielone Rabowice II от Greenbud, Rabowice Park от SOVO, OlszyNOWA от Chronos, Barwne) — шум стройки и рост трафика неизбежны; параллельно строится обход Swarzędza (ul. Rabowicka–ul. Średzka, завершение январь 2027), что обещает снижение транзитного трафика. Для отдыха — Jezioro Swarzędzkie с пляжем, Dolina Cybiny и Malta в 10–15 мин езды; в самой деревне запланирован небольшой парк у сельского клуба и велопешеходная дорожка вдоль озера (на стадии документации). Кафе, ресторанов и какой-либо атмосферы в Rabowice нет — полная загородная тишина с полями вокруг; всё общепит и развлечения — в Swarzędzu или Poznani, куда без машины добраться крайне неудобно.",
    "Gowarzewo":            "Gowarzewo — деревня в гмине Клешчево (повят Познань), вторая по населению в муниципалитете, ~8,6 км², строго говоря не Свожендз: ни трамвая, ни PKP нет — только автобус MPK линии 431 (Rondo Rataje — Kleszczewo/Park) с остановками Gowarzewo/Akacjowa, Gowarzewo/Jesienna и др.; от деревни до Rondo Rataje ~26–29 минут, далее пересадка на трамвай до центра — итого 45–55 минут до Старого рынка. Из магазинов подтверждены Biedronka и Żabka; ресторанная жизнь практически отсутствует — на весь район одно заведение (Kociołek при ul. Siekierecka 24b). Детская инфраструктура есть: два детсада — публичный «Wesoły Gawroszek» (ул. Kleszczewo 3, 6:00–17:00) и частный Balbinka (ул. Malinowa 5), плюс ясли; очереди умеренные по меркам пригорода. Активная стройка: реализуется ЖК «4 Pory Roku» (3 фазы, 6 домов в первой очереди, бюджет 8–37 млн злотых); форумы (SkyscraperCity) прямо называют Gowarzewo «наиболее динамично застраивающимся» в гмине — жители предупреждают об отставании инфраструктуры от темпов застройки. Главный плюс — в 2017–2018 завершена реконструкция дороги 2410P (Kleszczewo–Gowarzewo–Zalasewo, 6,8 км, 24,2 млн злотых): дорога расширена до 7 м, построено 5,9 км велодорожек и 2 кольцевых перекрёстка в самом Gowarzewo; тихая зелёная локация с остатками дворянского парка, но кафе, ресторанов и ночной жизни практически нет — чистый спальный пригород с очень долгим путём в центр.",
    "Jasin":            "Яшин — сельская гмина в составе Сважендза, ~15 км к востоку от центра Познани, разрезана надвое национальной трассой №92: южная часть — крупный торговый комплекс ETC с супермаркетами, аптеками и сервисами, северная — жилая застройка (1 887 жителей на 2024 г.). Транспорт двухуровневый: автобус 406 (Swarzędzkie Przedsiębiorstwo Komunalne, отдельный тариф — не ZTM) идёт от остановки Jasin/Centrum Handlowe ETC до Rondo Śródka за ~30 мин, плюс пригородные электрички PKP Swarzędz–Poznań Główny — всего 9–10 минут, поезда с 04:45 до 23:36; до станции Swarzędz от жилой части Яшина нужно добраться автобусом или на велосипеде. Промышленная нагрузка высокая: в самом Яшине расположены гигантский логистический центр CLIP (инвестиция 75–300 млн злотых), заводы Blum Polska, Magna Automotive, Radaway, Fol-Poz — тяжёлые грузовики, промышленный шум и сложная логистика на дорогах являются реальной проблемой. Новая жилая застройка — «Nowy Jasin» от Greenbud Development на ул. Вжесиньска: двухуровневые таунхаусы 75–79 м² с садами, фазы III сданы в 2024–2025 гг., но покупатели жаловались на строительные дефекты (требовалась замена оконных рам) и задержки сдачи; девелопер получает 2,5/5 по количеству дефектов. Трамвай из Познани до Сважендза (и потенциально через Яшин) остаётся под вопросом: в 2025 г. проведён анализ осуществимости, но в ноябре 2025 г. появились публикации о том, что трамвай «может не зайти в Сважендз» из-за высоких затрат, технической сложности развязки Антонинек и конкуренции с уже существующей железной дорогой; реализация — горизонт неопределён. Для покупателей жилья ключевые риски: близость индустриальной зоны с тяжёлым трафиком на №92, отдельный транспортный тариф автобуса, отсутствие трамвайного сообщения в обозримой перспективе; плюсы — ETC прямо под боком, озеро Сважендзке и велодорожки, быстрые электрички до центра Познани.",
    "Gwiazdowo":            "Gwiazdowo — это деревня (331 житель по переписи 2021 г.) в гмине Костшин-Великопольски, в 20 км к востоку от центра Познани (не в черте города): не путать с районами самого Познани. Транспорт: местный автобус линии 461 (Костшин — Гвяздово — Ягодно) связывает деревню с ж/д станцией Kostrzyn Wielkopolski, откуда Koleje Wielkopolskie идут до Познани за 28–36 мин (23 пары в будни), но жители жалуются на рассинхронизацию: автобус приходит на вокзал уже после отправления поезда; до A2/S5 — 5 мин на машине, до Рондо Шродка/Поснании — 20 мин. Инфраструктура Костшина в 3 км: Biedronka, Netto, Chata Polska, Dino, аптеки, амбулатория, банки, начальная школа и детсад — всё это в Костшине, но не в самой деревне. Активная застройка: три параллельных девелоперских проекта — Osiedle Gwiazdowo (SOVO, рядом с историческим Парком Дворским 30 000 м²), Nowe Gwiazdowo (Invest Complex, 450+ квартир, плановые коммерческие площади 10 000 м² и спортзоны) и Młode Gwiazdowo; в 2024 г. сдано 116 новых объектов; при проверке квартир Invest Complex выявлены значительные проблемы с влагой и качеством стяжки. Зелень: заповедный парк усадьбы вплотную к осиде, лес к западу, инфраструктура для отдыха (площадки, поля) — только внутри новых ЖК; общественных кафе и ресторанов в самой деревне нет, гастро-жизнь сосредоточена в Костшине. Перспективы: новая автобусная линия перед осиде заявлена девелопером, но пока не введена; деревня активно растёт (+45 жителей за 2022 г.), однако городская инфраструктура (школа в пешей доступности, трамвай) по-прежнему отсутствует — это пригородный посёлок с сельским укладом и автомобильной зависимостью.",
    "Gruszczyn":            "Транспорт слабый: единственная прямая связь с Познанью — минибус лин. 416 (Gruszczyn → Zieliniec → ст. Antoninek → ул. Могиленьска), курсирует только в будни с 6:00 до 19:00 раз в 60 минут; на ст. Antoninek пересадка на PKM-электричку до центра Познани (~30 мин суммарно), интервал поездов 30 мин; на машине до Рондо Средка — 20 мин. Местная торговля ограничена Жабкой и парой мясных лавок — крупные супермаркеты (Kaufland, Lidl, Biedronka, Intermarché, ТЦ ETC) находятся в Сваже в 3 км. Школ в деревне нет: дети едут в Свожедж (~3 км), там же поликлиники и банки; из детских садов на месте работают только частные Tygryski (Swarzędzka 33-35) и Słoniki (Swarzędzka 59). Природа — сильная сторона: прямой выход в лес, Jezioro Swarzędzkie в 1 км, велодорожка через деревню от Победзиска до Malta в Познани, два конных центра, рядом Park Krajobrazowy Puszcza Zielonka. Застройка активная и хаотичная: работают девелоперы Nowy Gruszczyn, Osiedle na Wzgórzu (Planetbud, отзывы 2023 — влажность, дефекты окон) и ещё несколько проектов; многие новые улицы — грунтовые без покрытия, канализация подключена не везде; в 2022 году построен путепровод под железной дорогой, что улучшило связь с Антонинком. Население выросло с ~1200 до 3368 чел. (перепись 2021), деревня активно расширяется, но инфраструктура отстаёт от темпов строительства — типичная история пригорода без чёткого плана развития сервисов.",
    "Konarzewo":            "Konarzewo — деревня в гмине Допево, 15 км к юго-западу от центра Познани; единственный автобус — линия 703 ZTM (Konarzewo/Pętla → Górczyn PKM), полный маршрут ~44 минуты, пересадка на трамвай или PKM нужна — реальное время до Старого Рынка составляет 55–70 мин; машиной по S5 — 20–25 мин до центра. Прямо у деревни — развязка S5/A2: жители жалуются на шум от автострады и загрязнение воздуха фурами (экранозащита только у ул. Млыньска), а сама инфраструктура у виадука опасна — тротуар обрывается в песок без ограждений. В самом Коначево есть Dino (Torfowa 1, открыт до 22:30), школа им. Сенкевича (ул. Szkolna 16), детсад Madra Sowa и ясли Bajka; Biedronka — в Допево (~4 км), Lidl — в Скожево; аптек и банков в самой деревне нет, нужно ехать в Допево или Комóрники. Деревня находится в буферной зоне Великопольского национального парка (WPN): 100+ км веломаршрутов прямо от дома, зона строгой охраны «Тшчелиньске Багно» в 5 км, пруд и спортплощадка Doly Konarzewskie в центре (но обслуживаются плохо — жители в 2019 г. называли место «одуванчиковой плантацией»); запланирована велодорожка Тшчелин–Коначево, завершение — ноябрь 2027. Новое строительство — единичные дома от застройщиков (ул. Млыньска, сдача 2025–2026), массовой застройки пока нет, но МПЗП по ул. Познаньска открывает жилую зону; местный блог 2019 г. фиксирует, что гмина Допево системно недофинансирует Коначево в пользу Скожево и Комóрников — нехватка тротуаров, освещения и озеленения.",
    "Kleszczewo":            "Транспорт: автобусы ZTM Poznań линий 431 и 432 связывают Kleszczewo с Rondo Rataje (восток Познани) за ~33–44 минуты, в рамках единого тарифа (интеграция с ноября 2017 г.); внутри гмины курсирует бесплатная линия 488 (через Покlatki–Нагradowice–Крыжовники–Марковице) и 489 на Сваженж; железной дороги в гмине нет, ближайшая станция PKP — в Сваженже (~6 км). Инфраструктура торговли и услуг минимальна: в центре Kleszczewo — несколько небольших продуктовых магазинов, почта, аптека, ОПС; крупных сетей (Biedronka/Lidl) в самом посёлке нет — за ними ездят в Сваженж или Познань; ресторанов и кафе практически нет — гастрономическая пустыня. Школа: Zespół Szkół в Kleszczewo (472 ученика на 2022/23), плюс школы в Тулцах и Говаженво; предсадиковая очередь перегружена — с 2023/24 уч. года невозможно открыть дополнительную группу из-за нехватки места, строится новое муниципальное предsadzole в Kleszczewo (7 групп, ввод в строй к 2024–2025). Зелень и отдых: парк в Kleszczewo с прудом, помостом и фонтаном; природная тропа «Skarby lasu»; реконструкция исторического парка в Коморникax с 2022 г.; многофункциональные спортивные площадки и стадион; велодорожки связывают gmina с соседними муниципалитетами. Стройка и рост: gmina стремительно растёт (с ~9 000 до 10 000+ жителей); единственный крупный девелоперский проект — Kleszczewo Park (40 квартир от 388 000 PLN, ~7 700 PLN/м²), VI-я очередь таунхаусов сдана в 2025 г.; инфраструктура не успевает за приростом населения — главная жалоба жителей. Специфика локации: гмина расположена к востоку от Познани в точке пересечения автомагистрали A2 и экспрессовой S5 (узел Познань-Всхуд), в 15–20 км от центра города; рядом логистический центр в Сродке (тяжёлый грузовой трафик по Дороге 434 из-за отсутствия прямой связки S5–S11, вопрос обсуждался в Сейме в 2024 г.); территория тихая, безопасная, ориентирована на молодые семьи, бегущие из Познания, но лишённая городского комфорта.",
    "Czapury":            "Czapury — деревня в гмине Мосина (повят Познань), примерно 7 км к югу от центра Познани, с населением около 1900 человек, активно застраиваемая несколькими крупными девелоперами (Family House: Osiedle Leśne — уже 450+ домов/квартир, идёт IV этап на 174 квартиры; Osiedle Poznańskie — 34 многоквартирных дома; Osiedle Zacisze — 26 таунхаусов, сдача конец 2025). Главная транспортная проблема — единственный выезд в сторону Познани через железнодорожный переезд на Старолэке, один из самых загруженных в Польше (17 000 авто + 189 поездов в сутки), создающий многокилометровые пробки: дорога до центра 25 мин вне пробок и 40+ мин в часы пик; прямой электрички нет, автобус-527 идёт до Старолэки, откуда трамвай до центра. Инфраструктура крайне слабая для такого масштаба застройки: из магазинов только Жабка и пара мелких лавок на месте, крупный шопинг — в Познани или Дашевице, кафе и ресторанов практически нет. Канализация до сих пор не везде проведена (Aquanet строит сети в 2025 году), жители Osiedle Leśne публично жаловались на обман со стороны застройщика и отсутствие обещанной инфраструктуры (\"czujemy się jak świnie w błocie\"). Плюсы: непосредственная близость к лесу и Великопольскому национальному парку, конный клуб, пляж Glinianki в Мосине (20 мин), тихая среда; планируется новый мост через Варту в сторону Любоня и реконструкция переезда на Старолэке (стоимость ~150 млн злотых, финансирование не обеспечено). Школа им. Аркадия Фидлера в Чапурах была расширена (10 новых классов, спортзал), есть несколько частных садиков (Happy House, Akademia Uśmiechu), однако отзывы о школе неоднозначны. Вывод: место подходит людям с личным транспортом, ценящим природу и готовым к отсутствию городского комфорта и стройке вокруг ещё минимум 3-5 лет.",
    "Gołuski":            "Gołuski — деревня в гмине Допево (не в черте Познани), в 12–15 км к юго-западу от центра города: автобус 710 идёт до конечной Górczyn PKM (~40 мин, пересадка на трамвай), линия 716 — до Junikowo (~25 мин, 19 остановок), муниципальная бесплатная линия 795 соединяет с соседним Palędzie; прямой трамвай отсутствует, PKP — только через Допево. Инфраструктура крайне скудная: один продуктовый магазин, заведение MŁYN Bistro & Pizza на ул. Szkolna 2, ни банка, ни аптеки в самой деревне; ближайшие полноценные магазины и сервисы — в Допево или Дзялыне. В деревне есть Park Wiejski с футбольным полем, уличными тренажёрами и детской площадкой, свежий воздух и сельский характер — но никакой городской атмосферы. Собственной школы в Гоуски нет: дети ездят в Zespół Szkolno-Przedszkolny в Допево, запись в предсаد — через систему гмины с конкурсом критериев. Главная проблема района — SEGRO Logistics Park Poznań Gołuski (~50 000 кв.м складов на 11 га): склады стоят в 55 метрах от жилого района Leśne (в документах было заявлено 240 м), тяжёлые фуры пробираются через деревенские улицы (прямого выезда на S5/A2 нет), дорога ul. Szkolna не рассчитана на интенсивный грузовой трафик — жители публично протестовали ещё с 2021 года, называя ситуацию «gigantycznym przekrętem»; в июле 2026 года в деревне продолжаются дорожные работы, связанные с изменением организации движения.",
    "Wiry":            "Автобусы 603/610/614/701 ZTM + бесплатный муниципальный для жителей Мосины. Чистый воздух, тишина, лесные массивы. Жители пишут, что дорога в Познань «трагическая» — электрички переполнены, в вагоны в часы пик не пробиться.",
    "Sapowice":            "Sapowice — деревня в гмине Стэшев, в 25 км от центра Познани, расположена у озера Стрыковске (305 га, пляж в 800 м) и вплотную к Велькопольскому национальному парку — место природное, тихое и практически лишённое городской инфраструктуры. Единственное общественное сообщение — автобус PKS Познань лinia 19 до Познань-Главный, курсирующий лишь несколько раз в день по будням (зафиксировано отправление в 13:10); машина обязательна — по трассе S5 до центра Познани около 25 минут. В самой деревне магазинов и врачей нет: за продуктами — в Стрыкув (4 км, Dino, Lewiatan, аптека, железнодорожная станция PKP) или в Стэшев (8 км, Biedronka, Netto, Lidl, поликлиника, школы, детсады); районный форум жителей на sapowice.istrefa.com полностью пуст — комьюнити фактически не сформировано. Ведётся камерная застройка: 33 участка под ИЖС (504–599 м²) с подведёнными коммуникациями и проектами домов в цене — рынок ориентирован скорее на тех, кто ищет дачно-постоянный формат, а не городской пригород. Летом у озера оживлённо (купание, велодорожки до Стрыкува и Стэшева, каяки, рыбалка, Nordic walking в нацпарке), зимой — «тихо, пусто и ностальгично» по словам самого застройщика; место категорически не подходит тем, кто рассчитывает жить без личного автомобиля или нуждается в шаговой доступности услуг.",
    "Szczytniki":            "Szczytniki — деревня в гмине Кёрник, ~10 км от центра Познани: трамваев нет, только автобусы 511 и 512 (конечная Szczytniki/Pętla), дорога до Rondo Rataje занимает ~50 минут; с машиной — ~25 минут до центра, выезд на S11 рядом, без авто жизнь крайне неудобна. Ближайшие крупные магазины и аптеки — в Кёрнике (~3 км), на месте есть лишь несколько локальных предсзкол (Mądra Sowa, Wodnik Szuwarek, Tęcza), а ближайшая начальная школа — в Каминках (~3 км); новая SP nr 3 в Bnin (соседний район) должна открыться только в 2027 году, школьный комплекс — в 2029-м, что критично при взрывном росте населения (536% за 20 лет). Зелень отличная: 60-километровое велокольцо Kórnicki Pierścień Rowerowy, Jezioro Kórnickie (92 га, 3,8 км троп вдоль воды), опытный лес — всё в шаговой доступности. Район — активная стройка: идут проекты Nowe Szczytniki, Osiedle Azaliowe, Osiedle Malarska, пробки от грузовиков, пыль; петля автобуса на ul. Wspólna была закрыта с сентября 2025 года на дорожные работы. Из инфраструктурных плюсов: в 2025-2026 годах гмина строит chodnik при ul. Mostowej, новое освещение, модернизирует остановки и пешеходные переходы; в ноябре 2024 года разразился скандал вокруг нового studium — часть участков в Szczytniki переведена из жилых в зелёные зоны, что ударило по инвесторам. Итог: тихое, зелёное, дешевле Ратай, но без машины — ловушка, школ на всех не хватает, а стройка вокруг продлится ещё минимум 3-5 лет.",
    "Palędzie":            "Ж/д станция PKP Palędzie — большой плюс. Автобусы 727/729 + новая линия 728 (2026) + бесплатный муниципальный. Главная беда — ж/д переезд закрыт большую часть суток, создавая огромные пробки; единственное решение — путепровод, который пока лишь обсуждается.",
    "Strykowo":            "Strykowo — деревня в гмине Стэшев (Gmina Stęszew), повят познаньский, ~1 500 жителей (выросло на 34% с 1998 г.), расположена в 25 км юго-западнее центра Познани вдоль национальной дороги 32 (на Лешно), экспрессовая S5 в 5 км. Транспорт: дизельный поезд Koleje Wielkopolskie (линия Познань–Волштын) от станции Strykowo Poznańskie до Познань Главный — около 33 мин, примерно 1 раз в час; автобус PKS Poznań лини 19 (маршрут Познань–Бук–Стрыково–Стэшев) — единственный автобус, кроссы редкие; ZTM-автобусов городского Познани нет и не ожидается в ближайшее время (несколько попыток подключения провалились из-за затрат); проездной BTK на поезд+городской транспорт Познани — 219 злотых/мес. Магазины: один Dino (ul. Bukowska 19) и три мелких частных магазина (Anka, Gościniec, Mati) — ни Biedronka, ни Lidl, ни Kaufland в самой деревне нет, ближайший крупный выбор в Стэшеве или Буке. Образование: единый комплекс ZSP w Strykowie (ul. Bukowska 2) — детский сад (4 группы, 82 ребёнка) и начальная школа (9 классов, 163 ученика); запись в детсад ограничена объёмом заведения. Зелень: деревня с улицами Leśna, Łąkowa, Parkowa — сельский характер с доступом к полям; до Познани ездят за кафе и ресторанами — в самом Стрыково лишь приходской костёл св. Максимилиана Кольбе и минимальная инфраструктура. Перспективы: планируется узел Park&Ride при станции в рамках Познаньской Метрополитальной Железной Дороги (PKM); рост застройки умеренный (10 квартир в 2024 г.); отсутствие ZTM-автобуса — главная и хроническая жалоба жителей на форуме Стэшева.",
    "Napachanie":            "Napachanie — небольшая деревня в гмине Рокетница (повят познаньский), соединённая с Познанью автобусом ZTM линии 882 (остановки Napachanie/Park, Napachanie/Starzyńska, Napachanie/Kokoszczyńska) до узлового пересадочного пункта Rokietnica/Węzeł Przesiadkowy, откуда электричкой PKP до Познань-Главного около 15–20 минут — итого дорога до центра занимает примерно 35–50 минут в зависимости от стыковки. В самой деревне есть собственный Zespół Szkolno-Przedszkolny (ул. Познаньска 26) — государственная школа 1–8 классов с детсадом (3–6 лет), работает с 6:00 до 17:00, включает бесплатный английский и ритмику; очередей в садик в открытых источниках не зафиксировано, набор через систему nabor.pcss.pl. Магазины, аптеки, кафе в самом Напаханье фактически отсутствуют — всё это в соседней Рокетнице (2–3 км), деревня сохраняет сельский характер с агротуристическими усадьбами и историческим дворцом Рудольфа Грибеля. Активно идут работы по МПЗП: приняты планы застройки на участках вдоль ул. Рокетницкой, Старжиньской, Лесной и в зоне трассы S11 (резолюция XII/102/2024 от ноября 2024), что означает потенциальный рост жилой застройки в ближайшие годы. Главный риск — прохождение будущей трассы S11 непосредственно через территорию Напаханья: в МПЗП выделена специальная зона \"rejon drogi ekspresowej S11\", строительство которой несёт шум и вибрации для прилегающих участков. Район подходит для тех, кто ценит тишину, зелень и сельскую среду при наличии собственного авто или готовности к длительному общественному транспорту; для семей с детьми плюс — местная школа, минус — практически нулевая пешая инфраструктура и угроза шумовой нагрузки от S11.",
    "Kórnik":            "Электричка PKP Kórnik — Poznań Główny идёт 19 минут (первый рейс в 5:47, последний в 22:44); в марте 2025 добавлены дополнительные автобусные рейсы KOMBUS до ст. Szczodrzykowo, линия 590 связывает Bnin и Kórnik PKM с каждым поездом включая выходные, а в августе 2025 анонсированы ещё большая частота и лучшая синхронизация автобусов. В самом Кóрнике есть Lidl, Intermarché, Netto, Polo, Biedronka; в Борувце — Biedronka; на новых окраинных осёдлях — лишь мелкие магазинчики. Главная бытовая проблема: военная база Krzesiny с F-16 — шум реально беспокоит (около 1500 судебных исков о компенсации с 2007 года); в феврале 2026 gmina была вынуждена публично объяснять жителям, что «взрывы» над домами — плановые учения. Природа и отдых — сильная сторона: озёра Kórnickie, Skrzyneckie Duże и Bnińskie с пляжем на Błониях, замок с парком, арборетум; гастрономия небедная — Tawerna pod Żaglami над озером, Paleta, Prowent Bistro, Wielkie Nieba. Школы есть в Kamionki, Bnin, Radzewo, Szczodrzykowo; в Bnin планируется новая начальная школа и лицей; образование составляет более 1/3 бюджета gminy. Gmina разрабатывает стратегию развития до 2034 года: рост населения, новые осёдля (Szczytnik, Kamionki Północne на стадии консультаций по застройке), планируется набережная вдоль Jezioro Kórnickie и реконструкция парковок.",
    "Komorniki":            "Транспорт: автобусы ZTM/PUK — 10 муниципальных линий (702, 703, 707, 715, 716, 717, 728 и др.); с января 2026 г. линия 705 упразднена и заменена на 703; линия 702 до остановки Górczyn PKM — 21 мин каждые 20 мин, далее пересадка до центра (~35–40 мин суммарно); 24 автобуса в день, ~8400 рейсов/месяц; PKP-электричка также ходит на Познань; главный кошмар — пробки на ул. Гожевской/А2/S5 и у железнодорожного переезда в Пльевиска: построенный тоннель ситуацию не улучшил, жители говорят «стало хуже чем было». Инфраструктура и торговля: Auchan (ул. Глоговска 432), 19 ресторанов по TripAdvisor включая Restauracja Aleksandra (польская кухня, детский уголок), Uber Eats работает; атмосфера скорее спальная, не pub-scene. Школы и сады: 4 публичных детсада, 8 публичных с частным оператором, 7 частных, 10 яслей, 6 начальных школ — инфраструктура активно строится; Budimex достраивает пристройку к школе №2 в Пльевиска (срок — март 2026). Зелень: парки в пейзажном стиле XIX в. в Шрениаве, Пльевиска и Глухово; два маркированных велошляха (Иоанна Павла II и Независимости); дефицит велодорожек на уездных дорогах — системная жалоба жителей, на многих улицах нет даже тротуаров (особенно Росново). Стройка и проблемы: многие улицы до сих пор грунтовые; жители жалуются на мусорный полигон в Хомэцицах; застройщики не выполняют обещанную инфраструктуру; спортивно-рекреационный комплекс в Пльевиска — архитектурный конкурс осень 2025 г., разрешение на строй — осень 2027 г.; план ogólny выложен июнь 2026 г. Вывод: тихий, экономически сильный пригород в 14 км от центра Познани с неплохими школами и природой, но с реальными транспортными пробками в часы пик, дефицитом велоинфраструктуры и точечными проблемами ЖКХ.",
    "Złotniki (gmina Suchy Las)":            "Złotniki — сельская местность в богатой гмине Сухы Лас (одна из самых состоятельных гмин Польши), ~13 км к северу от центра Познани: электричка Koleje Wielkopolskie от станции Złotniki до Poznań Główny — 12–13 минут, но с пересадками или пешком до станции; автобус лин. 174 — 46–49 мин, пригородные линии ZKP 901/902/904/905 ходят до узла Os. Sobieskiego. В самих Złotniki инфраструктура минимальная: мелкие магазины, частный детсад/ясли (UL, Bajeczkowo), кафе нет почти вообще — за супермаркетом Lidl, аптекой, банком, медцентром и торговым центром Galeria Sucholeska ехать ~3,5 км до Suchego Lasu. Есть публичная и частная школы (Zespół Placówek Oświatowych, Społeczna Szkoła Podstawowa Promyczek) и предсадик Akademos прямо на территории осиедля Złotniki Park. Из плюсов: велодорожки вдоль ул. Łagiewnicka/Pawłowicka, маршруты MTB, близость заповедников Biedrusko и Rezerwatu Meteoryt Morasko, 10 камер видеонаблюдения и поднятые пешеходные переходы. Главная тревога: между жилыми осиедлями и железнодорожными путями запланировано строительство складско-производственных халл (ул. Kobaltowa/Obornicka) — идёт оценка воздействия на среду, что грозит шумом и трафиком грузовиков вплотную к Złotniki Park; жители Osiedla Grzybowego жалуются на конфликты соседей и отсутствие механизмов решения проблем.",
    "Lusowo (gmina Tarnowo Podgórne)":            "Транспорт слабый: автобус линии 805 (Юниково → Лусово → Тарново Подгурне) ходит только в будни с частотой раз в ~2 часа — 9 пар рейсов в день, плюс линия 802 до Ogrodów; до центра Познани на автобусе около 45–50 мин, на машине по шоссе 92/Буковской — 20 мин (S11 в 3 км). Инфраструктура базовая: в деревне есть собственная начальная школа (SP im. gen. Józefa Dowbora Muśnickiego, ul. Nowa 6) с дошкольным отделением при ней — запись через электронную систему только для жителей реципиентного округа; магазины в самом Лусово минимальные (Mila, Chata Polska), Lidl и Biedronka — в Тарново Подгурне. Природа — главный козырь: озеро Лусовске (121 га, глубина до 19,5 м, класс III) с обустроенным пляжем, outdoor-тренажёрами, волейболом, прокатом водного снаряжения и бесплатной парковкой; вокруг озера 10-километровый велопешеходный маршрут, через посёлок проходит Pierścień Rowerowy Dookoła Poznania. Еда и атмосфера: Restauracja Leśny Zakątek (ul. Poznańska) и Stara Wozownia (кухня + верховая езда для детей) прямо в Лусово; полноценный ресторанный выбор — в Тарново Подгурне (JUCCA, Pod Lwem). Застройка активная и вызывает споры: работают девелоперы Akropol Inwestycje, J&P Construction (Harmonia Lusowo), Nowe Lusowo, Osada Lusowo — в октябре 2024 г. жители вышли против изменений плана застройки, превращающего лесные зоны в жилые; местный интернет-форум фиксирует жалобы на то, что \"gmina robi się ciasna\" (посёлок переполняется). Gmina Tarnowo Podgórne — одна из богатейших в Польше за счёт крупной промышленно-логистической зоны (450 га), что даёт хороший бюджет на инфраструктуру, но приносит транзитный трафик и риски шума от S11; часть дорог в Лусово до сих пор не асфальтирована, а автобус без машины превращает жизнь в ежедневную логистическую задачу.",
    "Wiry (gmina Komorniki)":            "Wiry — деревня в gmina Komorniki (одна из богатейших гмин Польши по бюджету на жителя), 4 487 человек по переписи 2021 г., население удвоилось с 1998 г. — активный пригород с застройкой: в 2024 году сдано 59 новых домов средней площадью 131 м², несколько жилых проектов (Szmaragdowe Wiry — закрытое ОЖК из 24 домов, Wiry Komornicka от Q-2 с тепловыми насосами и фотовольтаикой, Akropol Inwestycje на ул. Познаньской). Транспорт: автобус ZTM линия 701 (Komorniki/Jeziorna — Górczyn PKM) с остановками Wiry/Kościół и Wiry/Laskowska, а также линии 603, 610, 614; через деревню проходит железнодорожная линия 357 (Sulechów — Luboń koło Poznania) — неэлектрифицированная, одноколейная, второстепенная, ведёт в Luboń, а не напрямую на Poznań Główny, поэтому электричка не является быстрым вариантом. Образование: 3 детских сада (182 ребёнка), 2 начальные школы (821 ученик, в т.ч. Вальдорфская социальная), 1 лицей — для деревни инфраструктура выше среднего. Зелень: у самого края Wielkopolski Park Narodowy (~7 600 га) с 85 км пешеходных и свыше 100 км велосипедных маршрутов, трасса EuroVelo R9 и Ring wokół Poznania. Проблемы: многие улицы до сих пор грунтовые (жители годами добиваются асфальта, ул. Kasztanowa — типичный пример), зафиксированы кражи из авто (поставлены камеры), велоинфраструктура между населёнными пунктами отсутствует; gmina Komorniki в целом богатая, но быстрый рост застройки опережает дорожную сеть.",
    "Palędzie (gmina Dopiewo, powiat poznański)":            "Транспорт: электричка PKP до Poznań Główny за 12–15 мин (интервал ~30 мин в час пик); автобусы 727 (Junikowo – Palędzie/Dworzec Kolejowy), 729 (до Ogrodów, ~41 мин до центра), с января 2026 добавлена новая линия 728 (Ogrody – Palędzie); жд-переезд на ул. Pocztowa регулярно перекрывает движение — идёт проектирование тоннеля под линией 3 (консультации завершены, строительство планируется). Инфраструктура скудная: в самом Palędzie — только Żabka на ul. Malinowa 35 и небольшой продуктовый Lajtgeber на Pocztowa 7, ни аптеки, ни ресторана, ни кафе — за всем едут в соседнюю Dąbrówkę или в город; детсад Bajkowa Wyspa (ul. Malinowa 38, 197 детей, психолог, логопед) есть, но начальной школы в деревне нет — дети ездят в Dąbrówkę. Главная хроническая проблема — промышленная рампа PKP/Dolata: шум, выхлопы и пыль с 06:00 до 22:00 пн–сб, штрафы Инспекции охраны среды с 2020 года ситуацию не улучшили, жители регулярно протестуют. Застройка активная: несколько новых ЖК (Osiedle Leśne от Gephouse, Akropol Inwestycje на ul. Różana, дома от 649 000 PLN с 2025 г.), но часть улиц по-прежнему без твёрдого покрытия, тротуаров и освещения — типичная проблема быстрорастущего пригорода без опережающей инфраструктуры. Из плюсов: спорткомплекс «Sportowe Palędzie» (футбол, баскетбол, стрельба из лука, уличные тренажёры), пешие и беговые тропы в окрестных лесах, озеро Niepruszewskie с пляжем в 7–10 км, близость к трассе S11; до аэропорта Ławica ~10 км, до центра Познани ~14 км.",
    "Kamionki (gmina Kórnik, powiat poznański)":            "Kamionki — деревня в гмине Курник, 17 км к юго-востоку от центра Познани (~18 мин на машине), вблизи S11/A2 (10 км до автострады). Общественный транспорт: автобусы ZTM линий 512 и 527 (тарифная зона B — нужен билет A+B, дороже), конечная остановка 527 — Kamionki/Pętla, маршрут от Starołęka PKM занимает ~34 мин; в выходные расписание резко ухудшается — жители жалуются на пустые интервалы; есть железнодорожная остановка Kamionki Jezioro (Koleje Wielkopolskie, региональные поезда до Poznań Główny). Инфраструктура: Galeria Mini с супермаркетом, пекарней и аптекой; два продуктовых магазина; современный школьный комплекс 2015 года — начальная школа, детсад и ясли под одной крышей, спортзал и многофункциональные площадки; частный детский сад \"Tajemnicza Wyspa\". Зелень: ~70% территории гмины покрыто лесами, велокольцо Kórnicki Pierścień Rowerowy — 61 км; скейт-парк, игровые площадки. Активная застройка: работают Akropol Inwestycje, IDEAdeweloper, Solbud, Tefra House — дома-близнецы и таунхаусы от 299 до 519 тыс. злотых. Главные минусы: многие улицы без асфальта и нормального дренажа, часть домов без канализации (сети расширяются), слабый общественный транспорт в выходные, более высокие транспортные расходы из-за зоны B — для тех без машины это реальная проблема.",
}


# Неудобные промышленные объекты: (lat, lon, radius_km, penalty, name)
# penalty — сколько вычитается из итоговой оценки при попадании в радиус
# Sources: Aquanet, Veolia, ZZO, Wikipedia PL, OSM
_NUISANCE_SITES = [
    (52.430,  16.990,  4.0, 1.5, "ITPOK Spalarnia"),
    (52.436,  16.988,  5.0, 1.0, "EC Karolin (Veolia)"),
    (52.431,  16.959,  2.5, 1.2, "Oczyszczalnia LOŚ Serbska (Aquanet)"),
    (52.449,  16.981,  3.0, 1.5, "Oczyszczalnia COŚ Koziegłowy (Aquanet)"),
    (52.497,  16.888,  3.0, 1.2, "Składowisko ZZO Suchy Las"),
    (52.412,  17.031,  1.5, 0.8, "VW Antoninek (fabryka)"),
    (52.389,  16.887,  1.5, 0.8, "VW Odlewnia Wilda"),
    (52.328,  16.900,  3.0, 1.2, "Luvena SA Luboń (zakład chemiczny)"),
]

from math import radians, sin, cos, sqrt, atan2 as _atan2

def _haversine(lat1, lon1, lat2, lon2):
    R = 6371
    dl = radians(lat2 - lat1); do = radians(lon2 - lon1)
    a = sin(dl/2)**2 + cos(radians(lat1))*cos(radians(lat2))*sin(do/2)**2
    return R * 2 * _atan2(sqrt(a), sqrt(1 - a))

def _nuisance_penalty(lat, lon):
    """Total penalty for proximity to industrial/polluting sites (capped at 2.5)."""
    if lat is None or lon is None:
        return 0.0
    total = 0.0
    for slat, slon, radius, penalty, _ in _NUISANCE_SITES:
        dist = _haversine(lat, lon, slat, slon)
        if dist < radius:
            # linear: full penalty at 0, zero at radius boundary
            total += penalty * (1 - dist / radius)
    return round(min(2.5, total), 2)

def _noise_penalty(noise):
    """
    noise: dict {source: max_ldwn_dba} from noise_cache.json (GEOPOZ 2017, facade level).
    Returns penalty 0–1.0. Data is worst-case facade exposure; actual indoor levels
    depend on floor, glazing, orientation — so scale is intentionally soft.
    """
    if not noise:
        return 0.0
    max_ldwn = max(noise.values())
    if max_ldwn <= 60:
        return 0.0
    if max_ldwn <= 65:
        return 0.3
    if max_ldwn <= 70:
        return 0.6
    return 1.0

def _score_district(district, city):
    """Check district first, then city name."""
    if district and district in DISTRICT_SCORES:
        return float(DISTRICT_SCORES[district])
    if city and city in DISTRICT_SCORES:
        return float(DISTRICT_SCORES[city])
    return float(_DEFAULT_DISTRICT_SCORE)


def _score_price(price):
    # Calibrated for 700k+ segment (filter default = 700k)
    if price is None:
        return 5.0  # neutral, not redistributed
    if price <= 700_000:
        return 10.0
    if price <= 900_000:
        return 10.0 - 3.0 * (price - 700_000) / 200_000   # 700k→10, 900k→7
    if price <= 1_200_000:
        return max(0.0, 7.0 - 7.0 * (price - 900_000) / 300_000)  # 900k→7, 1200k→0
    return 0.0


def _score_area(area):
    if area is None:
        return 5.0
    if area < 70 or area > 120:
        return 0.0
    if 85 <= area <= 105:
        return 10.0
    if area < 85:
        return 4.0 + 6.0 * (area - 70) / 15   # 70→4, 85→10
    return 10.0 - 3.0 * (area - 105) / 15      # 105→10, 120→7


def _score_rooms(rooms):
    if rooms is None:
        return 5.0  # neutral, not redistributed
    if rooms == 4:
        return 10.0
    if rooms == 5:
        return 8.0
    if rooms in (3, 6):
        return 7.0
    return 3.0  # ≤2 or 7+


def _score_transport(tp, dist_tram, dist_center):
    d = dist_tram if dist_tram is not None else dist_center
    if d is None:
        return 5.0
    if tp == "dom":
        if d <= 2:   return 10.0
        if d <= 5:   return 10.0 - 1.0 * (d - 2) / 3   # 2→10, 5→9
        if d <= 10:  return max(6.0, 9.0 - 3.0 * (d - 5) / 5)  # 5→9, 10→6
        return max(0.0, 6.0 - 6.0 * (d - 10) / 5)      # 10→6, 15→0
    else:
        if d <= 0.5: return 10.0
        if d <= 1.5: return 10.0 - 2.0 * (d - 0.5)     # 0.5→10, 1.5→8
        if d <= 3:   return 8.0 - 2.0 * (d - 1.5) / 1.5  # 1.5→8, 3→6
        if d <= 5:   return max(0.0, 6.0 - 6.0 * (d - 3) / 2)  # 3→6, 5→0
        return 0.0


def _score_type(tp):
    return 10.0 if tp == "dom" else 8.0


_BASE_W = {
    "transport": 0.28,
    "district":  0.38,
    "price":     0.12,
    "area":      0.12,
    "rooms":     0.07,
    "type":      0.03,
}


def compute_score(price, area, rooms, tp, dist_tram, dist_center, district=None, city=None, lat=None, lon=None, noise=None):
    factors = [
        (_score_transport(tp, dist_tram, dist_center), _BASE_W["transport"]),
        (_score_district(district, city),               _BASE_W["district"]),
        (_score_price(price),                           _BASE_W["price"]),
        (_score_area(area),                             _BASE_W["area"]),
        (_score_rooms(rooms),                           _BASE_W["rooms"]),
        (_score_type(tp),                               _BASE_W["type"]),
    ]
    total_w = sum(w for _, w in factors)
    base = sum(sc * w for sc, w in factors) / total_w
    penalty = _nuisance_penalty(lat, lon) + _noise_penalty(noise)
    return round(max(0.0, base - penalty), 1)


def _f(v):
    try:
        return float(v) if v not in (None, "") else None
    except (ValueError, TypeError):
        return None


def _rooms(raw):
    if raw in (None, ""):
        return None
    if str(raw) == "7+":
        return 7
    try:
        return int(raw)
    except (ValueError, TypeError):
        return None


def score_from_csv(r):
    return compute_score(
        price=_f(r.get("price_zl")),
        area=_f(r.get("area_m2")),
        rooms=_rooms(r.get("rooms")),
        tp=r.get("type", ""),
        dist_tram=_f(r.get("drive_tram_km")) or _f(r.get("dist_tram")),
        dist_center=_f(r.get("drive_ratusz_km")) or _f(r.get("dist_km")),
        district=r.get("district", ""),
        city=r.get("city", ""),
    )


def score_from_jsrow(r):
    return compute_score(
        price=r.get("price"),
        area=r.get("area"),
        rooms=_rooms(r.get("rooms")),
        tp=r.get("type", ""),
        dist_tram=r.get("dist_tram"),
        dist_center=r.get("dist"),
        district=r.get("district", ""),
        city=r.get("city", ""),
        lat=r.get("lat"),
        lon=r.get("lon"),
        noise=r.get("noise"),
    )
